import React, { useState } from 'react';
import { CreditPackage } from '../types';
import { useAppContext } from '../contexts/AppContext';
import { 
    XMarkIcon, LockClosedIcon, CheckCircleIcon, 
    ShieldCheckIcon, ArrowLeftIcon, CreditCardIcon
} from './Icons';

interface PaymentModalProps {
    context: CreditPackage;
    onClose: () => void;
    onSuccess: (credits: number) => void;
}

const PaymentModal: React.FC<PaymentModalProps> = ({ context, onClose, onSuccess }) => {
    const { themeColor, paymentConfig } = useAppContext();
    const [status, setStatus] = useState<'idle' | 'redirecting' | 'awaiting' | 'success'>('idle');

    const handleRedirect = () => {
        setStatus('redirecting');

        // Simulação de redirecionamento. Em um app real, aqui abriria o link do Stripe/MercadoPago.
        setTimeout(() => {
            const paymentUrl = context.externalLink || paymentConfig.externalBaseUrl || 'https://checkout.stripe.com/pay/demo';
            window.open(paymentUrl, '_blank');
            setStatus('awaiting');
        }, 1500);
    };

    const handleConfirmSuccess = () => {
        setStatus('success');
        setTimeout(() => {
            onSuccess(context.credits);
            onClose();
        }, 2000);
    };

    const renderSummary = () => (
        <div className="space-y-6 animate-fade-in">
            <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 text-center">
                <p className="text-sm text-slate-500 uppercase font-bold tracking-wider mb-2">Resumo da Compra</p>
                <h3 className="text-3xl font-extrabold text-slate-800">{context.price}</h3>
                <div className="mt-4 flex items-center justify-center gap-2 text-green-600 bg-green-50 py-2 px-4 rounded-full border border-green-100 mx-auto w-fit">
                    <CheckCircleIcon className="w-5 h-5" />
                    <span className="font-bold">{context.credits} Créditos</span>
                </div>
            </div>

            <div className="space-y-4">
                <div className="flex items-start gap-3 p-4 bg-blue-50 rounded-xl border border-blue-100">
                    <ShieldCheckIcon className="w-6 h-6 text-blue-600 flex-shrink-0" />
                    <div>
                        <p className="text-sm font-bold text-blue-900">Pagamento Seguro Externo</p>
                        <p className="text-xs text-blue-700">Você será redirecionado para uma página de pagamento criptografada. Não coletamos seus dados de cartão aqui.</p>
                    </div>
                </div>

                <button 
                    onClick={handleRedirect}
                    className={`w-full bg-${themeColor}-600 text-white font-bold py-4 px-6 rounded-2xl shadow-lg hover:bg-${themeColor}-700 transition-all duration-200 transform hover:scale-[1.02] active:scale-100 flex items-center justify-center gap-3`}
                >
                    <span>Ir para Pagamento Seguro</span>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
                    </svg>
                </button>

                <p className="text-[10px] text-center text-slate-400">
                    Aceitamos Cartão de Crédito, Pix e Boleto através do checkout seguro.
                </p>
            </div>
        </div>
    );

    const renderRedirecting = () => (
        <div className="flex flex-col items-center justify-center h-80 text-center animate-fade-in">
             <div className={`animate-spin rounded-full h-16 w-16 border-4 border-slate-200 border-t-${themeColor}-600 mb-6`}></div>
             <p className="font-bold text-xl text-slate-700">Redirecionando...</p>
             <p className="text-sm text-slate-500 mt-2">Estamos preparando seu ambiente seguro de pagamento.</p>
        </div>
    );

    const renderAwaiting = () => (
        <div className="flex flex-col items-center justify-center h-80 text-center animate-fade-in px-4">
            <div className="w-20 h-20 bg-yellow-100 rounded-full flex items-center justify-center mb-6">
                <LockClosedIcon className="w-10 h-10 text-yellow-600" />
            </div>
            <h3 className="text-xl font-bold text-slate-800">Pagamento em Aberto</h3>
            <p className="text-sm text-slate-600 mt-2 mb-8">
                Uma nova aba foi aberta para você concluir o pagamento. Assim que terminar, clique no botão abaixo.
            </p>
            <div className="flex flex-col w-full gap-3">
                <button 
                    onClick={handleConfirmSuccess}
                    className="w-full bg-green-600 text-white font-bold py-3 px-6 rounded-xl shadow-md hover:bg-green-700 transition-all"
                >
                    Já realizei o pagamento
                </button>
                <button 
                    onClick={() => setStatus('idle')}
                    className="text-sm text-slate-500 hover:text-slate-700 font-semibold"
                >
                    Tentar novamente / Voltar
                </button>
            </div>
        </div>
    );

    const renderSuccess = () => (
        <div className="flex flex-col items-center justify-center h-80 text-center animate-fade-in">
            <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4">
                <CheckCircleIcon className="w-12 h-12 text-green-600" />
            </div>
            <h3 className="text-2xl font-bold text-slate-800">Créditos Adicionados!</h3>
            <p className="text-slate-600 mt-2">
                Seu pagamento foi confirmado com sucesso.
            </p>
        </div>
    );

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex justify-center items-center p-4 animate-fade-in" onClick={status === 'idle' ? onClose : undefined}>
            <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md relative overflow-hidden flex flex-col" onClick={(e) => e.stopPropagation()}>

                {/* Header */}
                <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">Finalizar Compra</h2>
                        <p className="text-xs text-slate-500 font-medium">{context.name}</p>
                    </div>
                    {status === 'idle' && (
                        <button onClick={onClose} className="text-slate-400 hover:bg-slate-100 rounded-full p-2 transition-colors">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    )}
                </div>

                {/* Content */}
                <div className="p-8">
                    {status === 'idle' && renderSummary()}
                    {status === 'redirecting' && renderRedirecting()}
                    {status === 'awaiting' && renderAwaiting()}
                    {status === 'success' && renderSuccess()}
                </div>

                {/* Footer Security */}
                <div className="p-4 bg-slate-50 border-t border-slate-100 flex flex-col items-center gap-2">
                    <div className="flex items-center gap-4 text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                        <div className="flex items-center gap-1.5">
                            <ShieldCheckIcon className="w-3.5 h-3.5 text-green-500" />
                            <span>Seguro</span>
                        </div>
                        <div className="flex items-center gap-1.5">
                            <LockClosedIcon className="w-3.5 h-3.5" />
                            <span>SSL</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default PaymentModal;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { User, SupportTicket, PaymentConfig } from '../types';
import { Logo } from './Logo';
import { useAppContext } from '../contexts/AppContext';
import { 
    UsersIcon, LogoutIcon, TrashIcon, SearchIcon,
    SparklesIcon, XMarkIcon, CheckBadgeIcon, ChartBarIcon, CurrencyDollarIcon,
    PencilSquareIcon, BriefcaseIcon, QuestionMarkCircleIcon, DashboardIcon, 
    Cog6ToothIcon, PaperAirplaneIcon, SwatchIcon, PresentationChartLineIcon,
    ClipboardListIcon, EyeIcon, NoSymbolIcon, IdentificationIcon, CreditCardIcon,
    LockClosedIcon, QrCodeIcon, DevicePhoneMobileIcon, LinkIcon
} from './Icons';
import AdminChart, { ChartDataItem } from './AdminChart';
import AdminCustomization from './AdminCustomization';
import AdminServices from './AdminServices';

type AdminView = 'dashboard' | 'users' | 'services' | 'finances' | 'support' | 'customize' | 'verifications' | 'payments';

const StatCard: React.FC<{ title: string; value: string | number; icon: React.ReactNode; themeColor: string }> = ({ title, value, icon, themeColor }) => (
    <div className="bg-white/60 backdrop-blur-sm border border-white/50 p-6 rounded-2xl shadow-lg flex items-center">
        <div className={`bg-${themeColor}-100 text-${themeColor}-600 rounded-xl p-3 mr-4`}>{icon}</div>
        <div>
            <p className="text-sm font-medium text-slate-500">{title}</p>
            <p className="text-3xl font-bold text-slate-800">{value}</p>
        </div>
    </div>
);

const AdminDashboard: React.FC = () => {
    const { allUsers, transactions, themeColor } = useAppContext();
    const users: User[] = Object.values(allUsers);

    const clientCount = users.filter(u => u.userType === 'client').length;
    const professionalCount = users.filter(u => u.userType === 'professional' && u.email !== 'conectechserver@gmail.com').length;
    const totalCreditsPurchased = transactions.filter(t => t.type === 'purchase').reduce((acc, t) => acc + t.amount, 0);

    const newUsersData: ChartDataItem[] = [
        { label: 'Maio', values: [{ value: 8, color: 'bg-sky-500', label: 'Clientes' }, { value: 3, color: 'bg-purple-500', label: 'Profissionais' }] },
        { label: 'Junho', values: [{ value: 12, color: 'bg-sky-500' }, { value: 5, color: 'bg-purple-500' }] },
        { label: 'Julho', values: [{ value: 15, color: 'bg-sky-500' }, { value: 7, color: 'bg-purple-500' }] },
    ];

    const creditsActivityData: ChartDataItem[] = [
        { label: 'Maio', values: [{ value: 250, color: 'bg-green-500', label: 'Comprados' }, { value: 120, color: 'bg-red-500', label: 'Gastos' }] },
        { label: 'Junho', values: [{ value: 310, color: 'bg-green-500' }, { value: 180, color: 'bg-red-500' }] },
        { label: 'Julho', values: [{ value: 450, color: 'bg-green-500' }, { value: 290, color: 'bg-red-500' }] },
    ];

    const topProfessionalsData: ChartDataItem[] = useMemo(() => {
        const professionalSpending = transactions
            .filter(t => t.type === 'expenditure' && allUsers[t.userId]?.userType === 'professional')
            .reduce<Record<string, number>>((acc, t) => {
                acc[t.userId] = (acc[t.userId] || 0) + 1; 
                return acc;
            }, {});

        return Object.entries(professionalSpending)
            .sort((a, b) => (b[1] as number) - (a[1] as number))
            .slice(0, 5)
            .map(([userId, unlocks]) => ({
                label: allUsers[userId]?.name || 'Desconhecido',
                values: [{ value: unlocks, color: `bg-${themeColor}-500` }]
            }));
    }, [transactions, allUsers, themeColor]);


    return (
        <div className="space-y-8 animate-fade-in">
             <h2 className="text-3xl font-bold text-slate-900">Dashboard</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <StatCard title="Total de Clientes" value={clientCount} icon={<UsersIcon className="w-6 h-6"/>} themeColor={themeColor} />
                <StatCard title="Total de Profissionais" value={professionalCount} icon={<BriefcaseIcon className="w-6 h-6"/>} themeColor={'purple'} />
                <StatCard title="Créditos Comprados (Total)" value={totalCreditsPurchased} icon={<ChartBarIcon className="w-6 h-6"/>} themeColor={'yellow'} />
            </div>

             <div className="mt-12 space-y-8">
                <h3 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
                    <PresentationChartLineIcon className="w-7 h-7 text-slate-500" />
                    Análises
                </h3>
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    <AdminChart title="Novos Usuários (Últimos 3 Meses)" data={newUsersData} />
                    <AdminChart title="Atividade de Créditos (Últimos 3 Meses)" data={creditsActivityData} />
                </div>
                <div className="grid grid-cols-1">
                    <AdminChart title="Profissionais Mais Ativos (por Desbloqueios)" data={topProfessionalsData} type="horizontalBar" showLegend={false} />
                </div>
            </div>
        </div>
    );
};

const AdminPaymentIntegration: React.FC = () => {
    const { themeColor, showToast, paymentConfig, setPaymentConfig, setPaymentGateway } = useAppContext();
    const [config, setConfig] = useState<PaymentConfig>(paymentConfig);

    useEffect(() => {
        setPaymentGateway('external');
    }, [setPaymentGateway]);

    const handleSave = () => {
        setPaymentConfig({ ...config, provider: 'external' });
        showToast('Configurações de link externo salvas!', 'success');
    };

    return (
        <div className="space-y-8 animate-fade-in pb-10">
            <h2 className="text-3xl font-bold text-slate-900">Integração de Pagamentos</h2>

            <div className="bg-white/90 backdrop-blur-md border border-white/50 p-8 rounded-3xl shadow-lg">
                <div className="flex items-center gap-4 mb-6">
                    <div className={`p-3 bg-${themeColor}-100 rounded-2xl text-${themeColor}-600`}>
                        <LinkIcon className="w-8 h-8" />
                    </div>
                    <div>
                        <h3 className="text-xl font-bold text-slate-800">Checkout Externo</h3>
                        <p className="text-sm text-slate-500">Configure um link único para seus recebimentos.</p>
                    </div>
                </div>

                <div className="space-y-6">
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-2">URL Base de Pagamento (Opcional)</label>
                        <input 
                            type="url" 
                            value={config.externalBaseUrl || ''}
                            onChange={e => setConfig({...config, externalBaseUrl: e.target.value})}
                            placeholder="https://checkout.stripe.com/p/minha-loja"
                            className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none font-mono text-sm"
                        />
                        <p className="text-[11px] text-slate-400 mt-2">Dica: Você pode usar links do Stripe Payment Links, Mercado Pago Checkout Pro ou PagSeguro.</p>
                    </div>

                    <div className="p-4 bg-yellow-50 rounded-2xl border border-yellow-100 flex items-start gap-3">
                        <QuestionMarkCircleIcon className="w-6 h-6 text-yellow-600 flex-shrink-0" />
                        <div className="text-xs text-yellow-800 leading-relaxed">
                            <p className="font-bold mb-1">Como funciona o modo sem backend?</p>
                            O usuário é enviado para o seu link. Após pagar, ele retornará ao app e clicará em "Já paguei". Os créditos serão adicionados automaticamente na sessão dele. Para um sistema 100% automático e seguro, um backend com webhooks seria necessário no futuro.
                        </div>
                    </div>
                </div>

                <div className="mt-8 pt-6 border-t border-slate-100 flex justify-end">
                    <button onClick={handleSave} className={`px-8 py-3 bg-${themeColor}-600 text-white font-bold rounded-xl shadow-md hover:bg-${themeColor}-700 transition-transform active:scale-95`}>
                        Salvar Configurações
                    </button>
                </div>
            </div>
        </div>
    );
};

const AdminPanel: React.FC = () => {
    const { logout, themeColor } = useAppContext();
    const [activeView, setActiveView] = useState<AdminView>('dashboard');

    const renderContent = () => {
        switch(activeView) {
            case 'dashboard': return <AdminDashboard />;
            case 'users': return <AdminUserManagement />;
            case 'verifications': return <AdminVerifications />;
            case 'finances': return <AdminFinancials />;
            case 'services': return <AdminServices />;
            case 'support': return <AdminSupportManagement />;
            case 'customize': return <AdminCustomization />;
            case 'payments': return <AdminPaymentIntegration />;
            default: return null;
        }
    };

    const navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: <DashboardIcon className="w-5 h-5 mr-3" /> },
        { id: 'users', label: 'Usuários', icon: <UsersIcon className="w-5 h-5 mr-3" /> },
        { id: 'verifications', label: 'Verificações', icon: <IdentificationIcon className="w-5 h-5 mr-3" /> },
        { id: 'services', label: 'Serviços', icon: <ClipboardListIcon className="w-5 h-5 mr-3" /> },
        { id: 'finances', label: 'Finanças', icon: <CurrencyDollarIcon className="w-5 h-5 mr-3" /> },
        { id: 'payments', label: 'Pagamentos', icon: <CreditCardIcon className="w-5 h-5 mr-3" /> },
        { id: 'support', label: 'Suporte', icon: <QuestionMarkCircleIcon className="w-5 h-5 mr-3" /> },
        { id: 'customize', label: 'Customização', icon: <Cog6ToothIcon className="w-5 h-5 mr-3" /> },
    ];

    return (
        <div className="flex h-screen bg-slate-100 font-sans">
            <aside className="flex flex-col w-64 bg-white/60 backdrop-blur-xl border-r border-slate-200/80 text-slate-800 flex-shrink-0">
                <div className="px-6 py-4 border-b border-slate-200/80"> <Logo /> </div>
                 <nav className="flex-grow p-4 space-y-2">
                    {navItems.map(item => (
                         <button
                            key={item.id}
                            onClick={() => setActiveView(item.id as AdminView)}
                            className={`flex items-center w-full px-3 py-2.5 text-sm font-medium rounded-lg transition-colors ${activeView === item.id ? `bg-${themeColor}-100 text-${themeColor}-700 font-semibold` : 'text-slate-600 hover:bg-slate-200/50'}`}
                        >
                            {item.icon}
                            <span>{item.label}</span>
                        </button>
                    ))}
                 </nav>
                 <div className="p-4 border-t border-slate-200/80">
                    <button onClick={logout} className="w-full text-left flex items-center px-3 py-2 text-sm text-slate-600 hover:bg-slate-200/50 rounded-lg transition-colors">
                        <LogoutIcon className="w-5 h-5 mr-3"/> Sair do Painel
                    </button>
                 </div>
            </aside>
            <main className="flex-1 overflow-y-auto p-4 sm:p-6 lg:p-8 bg-gradient-to-br from-slate-50 to-slate-200">
                <div className="max-w-7xl mx-auto">
                    {renderContent()}
                </div>
            </main>
        </div>
    );
};

