const UserEditModal: React.FC<{ user: User, onClose: () => void, onSave: (email: string, data: Partial<User>) => void }> = ({ user, onClose, onSave }) => {
    const [formData, setFormData] = useState<Partial<User>>(user);
    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setFormData(p => ({ ...p, [e.target.name]: e.target.value }));
    const handleSave = () => { onSave(user.email, formData); onClose(); };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex justify-center items-center p-4 animate-fade-in" onClick={onClose}>
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg relative animate-slide-up" onClick={e => e.stopPropagation()}>
