                    <div><label className="text-xs font-semibold text-slate-700">Nome</label><input name="name" value={formData.name || ''} onChange={handleChange} className="w-full p-2 bg-slate-50 border border-slate-300 text-slate-900 rounded-md mt-1 focus:ring-2 focus:ring-sky-500 focus:outline-none transition"/></div>
                    <div><label className="text-xs font-semibold text-slate-700">Email</label><input type="email" value={formData.email || ''} disabled className="w-full p-2 border border-slate-300 rounded-md mt-1 bg-slate-100 text-slate-500 cursor-not-allowed"/></div>
                    <div><label className="text-xs font-semibold text-slate-700">Telefone</label><input name="phoneNumber" value={formData.phoneNumber || ''} onChange={handleChange} className="w-full p-2 bg-slate-50 border border-slate-300 text-slate-900 rounded-md mt-1 focus:ring-2 focus:ring-sky-500 focus:outline-none transition"/></div>
