import React, { ErrorInfo, ReactNode } from 'react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

export class ErrorBoundary extends React.Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  private handleReset = () => {
    localStorage.clear();
    sessionStorage.clear();
    window.location.reload();
  }

  public render() {
    // Fix: Using an explicit cast for 'this' to resolve 'property props does not exist' error encountered in some TypeScript environments during render.
    const { children } = (this as any).props;

    if (this.state.hasError) {
      return (
        <div className="flex flex-col items-center justify-center h-screen bg-slate-50 p-6 text-center font-sans">
            <h1 className="text-3xl font-bold text-slate-900 mb-4">Ops! Algo deu errado.</h1>
            <p className="text-slate-600 mb-8 max-w-md">
                Encontramos um erro crítico ao carregar o aplicativo. Isso geralmente ocorre devido a dados salvos antigos ou incompatíveis.
            </p>
            {this.state.error && (
                <div className="bg-red-50 border border-red-200 p-4 rounded-lg mb-8 max-w-lg w-full overflow-auto text-left">
                    <p className="text-xs font-bold text-red-900 uppercase mb-1">Detalhe do Erro:</p>
                    <pre className="text-red-800 font-mono text-xs whitespace-pre-wrap break-all">
                        {this.state.error.toString()}
                    </pre>
                </div>
            )}
            <button 
                onClick={this.handleReset}
                className="bg-sky-600 text-white font-bold py-3 px-8 rounded-lg hover:bg-sky-700 transition shadow-lg flex items-center gap-2"
            >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
                </svg>
                Reiniciar e Limpar Dados
            </button>
        </div>
      );
    }

    return children;
  }
}

