import React, { useEffect } from 'react';
import Home from './components/Home';
import Auth from './components/Auth';
import UserProfile from './components/UserProfile';
import Orders from './components/Orders';
import BottomNav from './components/BottomNav';
import Credits from './components/Credits';
import Chat from './components/Chat';
import { useAppContext } from './contexts/AppContext';
import ProfessionalProfileView from './components/ProfessionalProfileView';
import AdminPanel from './components/AdminPanel';
import ReviewModal from './components/ReviewModal';
import PaymentModal from './components/PaymentModal';
import ChangePasswordModal from './components/ChangePasswordModal';
import CategoryView from './components/CategoryView';
import Marketplace from './components/Marketplace';
import RequestService from './components/RequestService';
import Header from './components/Header';
import SupportWidget from './components/SupportWidget';
import Toast from './components/Toast';
import ForgotPasswordModal from './components/ForgotPasswordModal';

const AppContent: React.FC = () => {
  const { 
    activeView, currentUser, 
    reviewContext, closeReviewModal, submitReview, 
    paymentContext, closePaymentModal, setUserCredits,
    isChangePasswordModalOpen, closeChangePasswordModal,
    isForgotPasswordModalOpen, closeForgotPasswordModal,
    fontFamily, toast, showToast, navigate
  } = useAppContext();

  // Monitorar parâmetros de URL para retorno automático da Stripe
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const status = params.get('payment_status') || params.get('status');
    const sessionId = params.get('session_id');

    if (status === 'success' && currentUser) {
        // Simulação de adição automática de créditos baseada no sucesso
        // Em um sistema real, a Stripe redirecionaria para uma URL com o valor ou o ID da sessão
        // Aqui simulamos a detecção de que o usuário voltou de uma compra bem-sucedida

        // Limpa a URL para não reprocessar ao dar F5
        window.history.replaceState({}, document.title, window.location.pathname);

        // Adiciona um valor padrão ou bônus por ter voltado da stripe (exemplo didático)
        // O ideal é que o webhook do backend faça isso, mas como é um Web App Frontend:
        showToast('Pagamento confirmado! Seus créditos estão sendo processados.', 'success');

        // Pequeno delay para simular o tempo de processamento "automático"
        setTimeout(() => {
            // Se o usuário clicou no pacote popular (25), por exemplo:
            const creditsToAdd = 25; 
            setUserCredits((currentUser.credits ?? 0) + creditsToAdd);
            showToast(`${creditsToAdd} créditos adicionados com sucesso!`, 'success');
        }, 2000);
    }
  }, [currentUser]);

  // The Admin Panel has its own layout and is rendered separately.
  if (activeView === 'adminPanel' && currentUser?.email === 'conectechserver@gmail.com') {
    return <AdminPanel />;
  }

  const fontClass = {
    'Inter': 'font-sans',
    'Roboto': 'font-roboto',
    'Lato': 'font-lato',
    'Poppins': 'font-poppins',
  }[fontFamily] || 'font-sans';


  const renderContent = () => {
    switch (activeView) {
      case 'home':
        return currentUser?.userType === 'professional' ? <Marketplace /> : <Home />;
      case 'orders':
        return currentUser ? <Orders /> : <Auth />;
      case 'marketplace':
         return currentUser?.userType === 'professional' ? <Marketplace /> : <Home />;
      case 'requestService':
         return currentUser?.userType === 'client' ? <RequestService /> : <Home />;
      case 'login':
        return <Auth />;
      case 'profile':
        return currentUser ? <UserProfile /> : <Auth />;
      case 'credits':
        return currentUser?.userType === 'professional' ? <Credits /> : <Home />;
      case 'chat':
        return currentUser ? <Chat /> : <Auth />;
      case 'professionalProfile':
        return <ProfessionalProfileView />;
      case 'categoryView':
        return <CategoryView />;
      case 'adminPanel':
        return <Home />;
      default:
        return <Home />;
    }
  };

  const handlePaymentSuccess = (credits: number) => {
    if (currentUser) {
        setUserCredits((currentUser.credits ?? 0) + credits);
        showToast(`${credits} créditos adicionados com sucesso!`, 'success');
    }
  };

  const handleChangePassword = () => {
    console.log(`Password change attempt for ${currentUser?.email}`);
    closeChangePasswordModal();
    showToast('Senha alterada com sucesso!', 'success');
  };

  return (
    <div className={`h-screen bg-slate-100 flex flex-col ${fontClass} select-none`}>
      <Header />
      <Toast 
        message={toast.message} 
        type={toast.type}
        visible={toast.visible} 
      />
      <div className="flex flex-1 overflow-hidden">
        <main className="flex-1 overflow-y-auto pb-20 md:pb-0">
          {renderContent()}
        </main>
      </div>
      {currentUser && <SupportWidget />}
      <BottomNav />
      {reviewContext && (
        <ReviewModal
          context={reviewContext}
          onClose={closeReviewModal}
          onSubmit={(review) => {
            if(reviewContext.service) {
               submitReview(reviewContext.service.name, reviewContext.orderId, review);
            }
            closeReviewModal();
          }}
        />
      )}
       {paymentContext && (
        <PaymentModal 
            context={paymentContext}
            onClose={closePaymentModal}
            onSuccess={handlePaymentSuccess}
        />
      )}
      {isChangePasswordModalOpen && (
          <ChangePasswordModal
              onClose={closeChangePasswordModal}
              onSubmit={handleChangePassword}
          />
      )}
      {isForgotPasswordModalOpen && (
          <ForgotPasswordModal
              onClose={closeForgotPasswordModal}
          />
      )}
    </div>
  );
}

const App: React.FC = () => {
  return <AppContent />;
};

export default App;

