// NOTE: A new instance is created for Veo to ensure the latest key is used.
// A shared instance can be used for other non-Veo calls.
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Search Grounding
export const searchWithGrounding = async (prompt: string) => {
  const ai = getAiClient();
  // FIX: Updated model to 'gemini-3-flash-preview' for basic text tasks with search grounding.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const text = response.text;
  const chunks: GroundingChunk[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = chunks
    .map(chunk => chunk.web)
    .filter(source => source && source.uri && source.title);

  return { text, sources };
};

export const generateReviewText = async (serviceName: string, professionalName: string, rating: number, userText: string) => {
  const ai = getAiClient();
  const prompt = `Você é um assistente prestativo para escrever avaliações de serviços. Um usuário deu uma avaliação de ${rating} de 5 estrelas para um serviço de "${serviceName}" realizado por "${professionalName}". Os pensamentos iniciais do usuário são: "${userText}". Com base nisso, escreva uma avaliação educada e útil em português do Brasil. Se a avaliação for alta (4-5 estrelas), seja positivo e detalhado. Se for baixa (1-2 estrelas), seja construtivo e específico sobre os problemas. Se for média (3 estrelas), seja equilibrado. Mantenha o texto conciso, com cerca de 2 a 4 frases.`;
  // FIX: Updated model to 'gemini-3-flash-preview' for basic text tasks.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });
  return response.text;
};

export const generateChatResponse = async (history: Content[], message: string) => {
  const ai = getAiClient();
  // FIX: Updated model to 'gemini-3-flash-preview' for basic text tasks.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [...history, {role: 'user', parts: [{text: message}]}],
  });

  return response.text;
};

export const analyzeImage = async (prompt: string, imageBase64: string, mimeType: string) => {
  const ai = getAiClient();
  const imagePart = {
    inlineData: {
      data: imageBase64,
      mimeType: mimeType,
    },
  };
  const textPart = {
    text: prompt,
  };

  // FIX: Updated model to 'gemini-3-flash-preview' for general image/text tasks.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [imagePart, textPart] },
  });

  return response.text;
};

type AspectRatio = '1:1' | '16:9' | '9:16' | '4:3' | '3:4';

// FIX: Updated generateImage to use gemini-2.5-flash-image with generateContent as per guidelines.
export const generateImage = async (prompt: string, aspectRatio: AspectRatio) => {
  const ai = getAiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: prompt,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio,
      },
    },
  });

  // FIX: Iterate through parts to find the image part, do not assume it is the first part.
  if (response.candidates && response.candidates[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return part.inlineData.data;
      }
    }
  }
  throw new Error("Não foi possível gerar a imagem.");
};

type VideoAspectRatio = '16:9' | '9:16';

export const generateVideo = async (prompt: string, imageBase64: string, mimeType: string, aspectRatio: VideoAspectRatio): Promise<VideosOperationResponse> => {
  const ai = getAiClient(); 

  const operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    image: {
      imageBytes: imageBase64,
      mimeType: mimeType,
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: aspectRatio
    }
  });
  return operation;
};

export const pollVideoOperation = async (operation: VideosOperationResponse): Promise<VideosOperationResponse> => {
  const ai = getAiClient();
  let currentOperation = operation;
  while (!currentOperation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    currentOperation = await ai.operations.getVideosOperation({ operation: currentOperation });
  }
  return currentOperation;
};

export const runComplexQuery = async (prompt: string) => {
  const ai = getAiClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    // thinkingConfig is only used for Gemini 3 and 2.5 series models if advanced reasoning is needed.
  });

  return response.text;
};

export const generateHeroVariations = async (baseContent: HeroContent): Promise<HeroContent[]> => {
  const ai = getAiClient();
  const prompt = `Com base no seguinte conteúdo de marketing para a seção "hero" de um site, gere 3 variações criativas e atraentes. Mantenha o tom profissional e focado em conectar talentos a oportunidades.

Conteúdo Base:
- Título: "${baseContent.title}"
- Destaque: "${baseContent.highlight}"
- Subtítulo: "${baseContent.subtitle}"

Retorne as variações como um array de objetos JSON.`;

  // FIX: Updated model to 'gemini-3-flash-preview' for basic text tasks.
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            highlight: { type: Type.STRING },
            subtitle: { type: Type.STRING },
          },
          required: ['title', 'highlight', 'subtitle'],
        },
      },
    },
  });

  const jsonStr = response.text.trim();
  return JSON.parse(jsonStr);
};

