            </div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Validando Transação</h2>
            <p className="text-slate-500 mt-3 max-w-xs mx-auto font-medium">
                Conectando aos servidores seguros da Stripe para liberar seus créditos...
            </p>
        </div>
    );
  }

  if (activeView === 'adminPanel' && currentUser?.email === 'conectechserver@gmail.com') {
    return <AdminPanel />;
  }

  const fontClass = {
    'Inter': 'font-sans',
    'Roboto': 'font-roboto',
    'Lato': 'font-lato',
    'Poppins': 'font-poppins',
  }[fontFamily] || 'font-sans';


  const renderContent = () => {
    switch (activeView) {
      case 'home':
        return currentUser?.userType === 'professional' ? <Marketplace /> : <Home />;
      case 'orders':
        return currentUser ? <Orders /> : <Auth />;
      case 'marketplace':
         return currentUser?.userType === 'professional' ? <Marketplace /> : <Home />;
      case 'requestService':
         return currentUser?.userType === 'client' ? <RequestService /> : <Home />;
      case 'login':
        return <Auth />;
      case 'profile':
        return currentUser ? <UserProfile /> : <Auth />;
      case 'credits':
        return currentUser?.userType === 'professional' ? <Credits /> : <Home />;
      case 'chat':
        return currentUser ? <Chat /> : <Auth />;
      case 'professionalProfile':
        return <ProfessionalProfileView />;
      case 'categoryView':
        return <CategoryView />;
      case 'adminPanel':
        return <Home />;
      default:
        return <Home />;
    }
  };

  const handlePaymentSuccess = (credits: number) => {
    if (currentUser) {
        setUserCredits((currentUser.credits ?? 0) + credits);
        showToast(`${credits} créditos adicionados com sucesso!`, 'success');
    }
  };

  return (
    <div className={`h-screen bg-slate-100 flex flex-col ${fontClass} select-none`}>
      <Header />
      <Toast 
        message={toast.message} 
        type={toast.type}
        visible={toast.visible} 
      />
      <div className="flex flex-1 overflow-hidden">
        <main className="flex-1 overflow-y-auto pb-20 md:pb-0">
          {renderContent()}
        </main>
      </div>
      {currentUser && <SupportWidget />}
      <BottomNav />
      {reviewContext && (
        <ReviewModal
          context={reviewContext}
          onClose={closeReviewModal}
          onSubmit={(review) => {
            if(reviewContext.service) {
               submitReview(reviewContext.service.name, reviewContext.orderId, review);
            }
            closeReviewModal();
          }}
        />
      )}
       {paymentContext && (
        <PaymentModal 
            context={paymentContext}
            onClose={closePaymentModal}
            onSuccess={handlePaymentSuccess}
        />
      )}
      {isChangePasswordModalOpen && (
          <ChangePasswordModal
              onClose={closeChangePasswordModal}
              onSubmit={() => {
                closeChangePasswordModal();
                showToast('Senha alterada com sucesso!', 'success');
              }}
          />
      )}
      {isForgotPasswordModalOpen && (
          <ForgotPasswordModal
              onClose={closeForgotPasswordModal}
          />
      )}
    </div>
  );
}

