// Helper function to get a deterministic image based on keyword
const getImage = (keyword: string) => {
    let hash = 0;
    for (let i = 0; i < keyword.length; i++) {
        const char = keyword.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; // Convert to 32bit integer
    }
    const lockId = Math.abs(hash % 1000);
    return `https://loremflickr.com/320/240/${keyword.split(',')[0]}?lock=${lockId}`;
};

