    const [searchTerm, setSearchTerm] = useState('');
    const [editingUser, setEditingUser] = useState<User | null>(null);

    const users = useMemo(() => Object.values(allUsers) as User[], [allUsers]);

    const filteredUsers = useMemo(() => {
        return users.filter(user => 
            user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            user.email.toLowerCase().includes(searchTerm.toLowerCase())
        );
    }, [users, searchTerm]);

    const handleDelete = (email: string) => {
        if (window.confirm(`Tem certeza que deseja remover ${email}?`)) {
            const newUsers = { ...allUsers };
            delete newUsers[email];
            setAllUsers(newUsers);
        }
    };

    return (
        <div className="space-y-8 animate-fade-in">
            {editingUser && <UserEditModal user={editingUser} onClose={() => setEditingUser(null)} onSave={updateUserProfile} />}
            <h2 className="text-3xl font-bold text-slate-900">Gerenciamento de Usuários</h2>
            <div className="bg-white/60 backdrop-blur-sm border border-white/50 rounded-2xl shadow-lg overflow-hidden">
