                <div className="overflow-x-auto"><table className="w-full text-sm text-left text-slate-500"><thead className="text-xs text-slate-700 uppercase bg-slate-50/50"><tr><th scope="col" className="px-6 py-3">Nome</th><th scope="col" className="px-6 py-3">Tipo</th><th scope="col" className="px-6 py-3">Status</th><th scope="col" className="px-6 py-3 text-center">Ações</th></tr></thead>
                        <tbody className="divide-y divide-slate-200/50">
                            {filteredUsers.map(user => (
                                <tr key={user.email} className="bg-white/50 hover:bg-slate-50/50">
                                    <td className="px-6 py-4 font-medium text-slate-900"><div className="flex items-center gap-3"><img src={user.avatar || `https://i.pravatar.cc/150?u=${user.email}`} className="w-8 h-8 rounded-full" /><div>{user.name}<div className="text-xs text-slate-500">{user.email}</div></div></div></td>
                                    <td className="px-6 py-4"><span className={`px-2 py-1 text-xs font-medium rounded-full ${user.userType === 'client' ? 'bg-green-100 text-green-800' : 'bg-purple-100 text-purple-800'}`}>{user.userType}</span></td>
                                    <td className="px-6 py-4">{user.verificationStatus === 'Verified' ? <span className="flex items-center text-xs font-semibold text-blue-600 gap-1"><CheckBadgeIcon className="w-4 h-4"/>Verificado</span> : <span className="text-xs text-slate-500">{user.verificationStatus || 'Não Verificado'}</span>}</td>
                                    <td className="px-6 py-4"><div className="flex items-center justify-center gap-1">
                                        <button onClick={() => setEditingUser(user)} className="p-2 text-slate-400 hover:bg-yellow-100 hover:text-yellow-600 rounded-full"> <PencilSquareIcon className="w-5 h-5"/> </button>
                                        {user.email !== 'conectechserver@gmail.com' && <button onClick={() => handleDelete(user.email)} className="p-2 text-slate-400 hover:bg-red-100 hover:text-red-600 rounded-full"><TrashIcon className="w-5 h-5"/></button>}
