const AppContext = createContext<AppContextType | undefined>(undefined);

// Chaves de armazenamento com versão para garantir integridade após mudanças
const STORAGE_KEYS = {
    ALL_USERS: 'chamaai_allUsers_v27',
    CURRENT_USER: 'chamaai_currentUser_v27',
    SERVICE_CATEGORIES: 'chamaai_categories_v27',
    CUSTOMIZATION: 'chamaai_custom_v27',
    CLIENT_ORDERS: 'chamaai_client_orders_v27',
    PROFESSIONAL_ORDERS: 'chamaai_prof_orders_v27',
    SERVICE_REQUESTS: 'chamaai_requests_v27'
};

export const AppContextProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {

    // Inicialização com Fallback Seguro
    const [allUsers, setAllUsers] = useState<Users>(() => secureStorage.getItem(STORAGE_KEYS.ALL_USERS) || initialUsers);
    const [currentUser, setCurrentUser] = useState<User | null>(() => secureStorage.getItem(STORAGE_KEYS.CURRENT_USER) || null);
    const [clientOrders, setClientOrders] = useState<ClientOrder[]>(() => secureStorage.getItem(STORAGE_KEYS.CLIENT_ORDERS) || initialClientOrders);
    const [professionalOrders, setProfessionalOrders] = useState<ProfessionalOrder[]>(() => secureStorage.getItem(STORAGE_KEYS.PROFESSIONAL_ORDERS) || initialProfessionalOrders);
    const [serviceRequests, setServiceRequests] = useState<ServiceRequest[]>(() => secureStorage.getItem(STORAGE_KEYS.SERVICE_REQUESTS) || initialServiceRequests);

    // Sincronização em tempo real com localStorage
    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.ALL_USERS, allUsers); }, [allUsers]);
    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.CURRENT_USER, currentUser); }, [currentUser]);
    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.CLIENT_ORDERS, clientOrders); }, [clientOrders]);
    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.PROFESSIONAL_ORDERS, professionalOrders); }, [professionalOrders]);
    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.SERVICE_REQUESTS, serviceRequests); }, [serviceRequests]);

    const isLoggedIn = !!currentUser;

    const login = async (user: User) => {
        const emailKey = user.email.toLowerCase();
        const userToLogin = allUsers[emailKey] || user;
        setCurrentUser(userToLogin);
        if(!allUsers[emailKey]) setAllUsers(prev => ({ ...prev, [emailKey]: user }));
        setActiveView(user.email === 'conectechserver@gmail.com' ? 'adminPanel' : 'home');
    };

    const logout = () => {
        setCurrentUser(null);
        setActiveView('home');
    };

    const setUserCredits = (newCreditCount: number) => {
        if (currentUser) {
            const updatedUser = { ...currentUser, credits: newCreditCount };
            setAllUsers(prev => ({ ...prev, [currentUser.email.toLowerCase()]: updatedUser }));
            setCurrentUser(updatedUser);
        }
    };

    const updateUserProfile = (email: string, updatedProfile: Partial<User>) => {
        setAllUsers(prev => {
            const current = prev[email.toLowerCase()];
            if (!current) return prev;
            return { ...prev, [email.toLowerCase()]: { ...current, ...updatedProfile } };
        });
        if (currentUser && currentUser.email.toLowerCase() === email.toLowerCase()) {
            setCurrentUser(prev => prev ? { ...prev, ...updatedProfile } : null);
        }
    };

    const adminChangeUserPassword = (email: string, newPassword: string) => {
        console.log(`Admin alterou a senha do usuário ${email} para: ${newPassword}`);
        showToast(`Senha de ${email} alterada com sucesso!`, 'success');
    };

    const [activeView, setActiveView] = useState<View>('home');
    const navigate = (view: View) => {
        if (['profile', 'orders', 'credits', 'chat', 'requestService'].includes(view) && !currentUser) {
            setActiveView('login');
        } else {
            setActiveView(view);
        }
    };

    const [viewedService, setViewedService] = useState<Service | null>(null);
    const [viewedCategory, setViewedCategory] = useState<string | null>(null);
    const [reviewContext, setReviewContext] = useState<ReviewContextType | null>(null);
    const [reviewedOrderIds, setReviewedOrderIds] = useState<number[]>([]);
    const [paymentContext, setPaymentContext] = useState<CreditPackage | null>(null);
    const [isChangePasswordModalOpen, setChangePasswordModalOpen] = useState(false);
    const [isForgotPasswordModalOpen, setForgotPasswordModalOpen] = useState(false);

    const [allServiceCategories, setAllServiceCategories] = useState<ServiceCategory[]>(() => secureStorage.getItem(STORAGE_KEYS.SERVICE_CATEGORIES) || servicesData);
    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.SERVICE_CATEGORIES, allServiceCategories); }, [allServiceCategories]);

    const [supportTickets, setSupportTickets] = useState<SupportTicket[]>(initialSupportTickets);
    const [transactions, setTransactions] = useState<Transaction[]>(initialTransactions);
    const [toast, setToast] = useState<ToastState>({ message: '', type: 'success', visible: false });
    const [requestServiceContext, setRequestServiceContext] = useState<{ category: string; service: string } | null>(null);

    const [customizationSettings, setCustomizationSettings] = useState(() => secureStorage.getItem(STORAGE_KEYS.CUSTOMIZATION) || {
        themeColor: 'sky',
        fontFamily: 'Inter',
        appName: 'Chama aí',
        appLogo: null,
        heroContent: { title: 'A plataforma completa para', highlight: 'seu projeto', subtitle: 'De desenvolvedores e designers a especialistas em marketing e finanças, encontre o talento que você precisa para decolar.' },
        abTestConfig: null,
        pricingTiers: { 'Baixa': 2, 'Média': 5, 'Alta': 10 },
        paymentGateway: 'stripe',
        paymentConfig: { provider: 'stripe', environment: 'sandbox', publishableKey: '', secretKey: '', webhookSecret: '' }
    });

    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.CUSTOMIZATION, customizationSettings); }, [customizationSettings]);

    const setAppName = (name: string) => setCustomizationSettings(s => ({...s, appName: name}));
    const setAppLogo = (logo: string | null) => setCustomizationSettings(s => ({...s, appLogo: logo}));
    const setFontFamily = (font: string) => setCustomizationSettings(s => ({...s, fontFamily: font}));
    const setThemeColor = (color: string) => setCustomizationSettings(s => ({...s, themeColor: color}));
    const setHeroContent = (content: HeroContent) => setCustomizationSettings(s => ({...s, heroContent: content}));
    const setPricingTiers = (tiers: PricingTiers) => setCustomizationSettings(s => ({...s, pricingTiers: tiers}));
    const setPaymentGateway = (gateway: string) => setCustomizationSettings(s => ({...s, paymentGateway: gateway}));
    const setPaymentConfig = (config: PaymentConfig) => setCustomizationSettings(s => ({...s, paymentConfig: config}));

    const showToast = (message: string, type: 'success' | 'error') => {
        setToast({ message, type, visible: true });
        setTimeout(() => setToast(prev => ({ ...prev, visible: false })), 3000);
    };

    const addServiceRequest = (request: Omit<ServiceRequest, 'id' | 'clientId' | 'status' | 'date' | 'unlockCost'>) => {
        if (!currentUser) return;
        const service = allServiceCategories.flatMap(c => c.services).find(s => s.name === request.serviceName);
        const cost = customizationSettings.pricingTiers[service?.complexity || 'Média'] || 2; 

        const newRequest: ServiceRequest = {
            ...request,
            id: Date.now(),
            clientId: currentUser.email,
            status: 'Aguardando Profissionais',
            date: new Date().toLocaleDateString('pt-BR'),
            unlockCost: cost,
        };
        setServiceRequests(prev => [newRequest, ...prev]);

        // Também adiciona à lista do cliente para não sumir
        const newClientOrder: ClientOrder = {
            id: newRequest.id,
            service: newRequest.title,
            date: newRequest.date,
            status: 'Aguardando Profissionais',
            clientId: currentUser.email,
            professional: { name: 'Aguardando...', email: 'pending@system.com', userType: 'professional' }
        };
        setClientOrders(prev => [newClientOrder, ...prev]);

        navigate('orders');
        showToast('Sua solicitação foi publicada!', 'success');
    };

    const completeServiceByProfessional = (orderId: number) => {
        const updateStatus = (o: any) => o.id === orderId ? { ...o, status: 'Concluído pelo Profissional' } : o;
        setProfessionalOrders(prev => prev.map(updateStatus));
        setClientOrders(prev => prev.map(updateStatus));
        setServiceRequests(prev => prev.map(r => r.id === orderId ? { ...r, status: 'Concluído pelo Profissional' } : r));
        showToast('Trabalho marcado como concluído!', 'success');
    };

    const finalizeServiceByClient = (orderId: number) => {
        const updateStatus = (o: any) => o.id === orderId ? { ...o, status: 'Finalizado' } : o;
        setClientOrders(prev => prev.map(updateStatus));
        setProfessionalOrders(prev => prev.map(updateStatus));
        setServiceRequests(prev => prev.map(r => r.id === orderId ? { ...r, status: 'Finalizado' } : r));
        showToast('Serviço finalizado com sucesso!', 'success');
    };

    const newOrdersCount = useMemo(() => professionalOrders.filter(o => o.status === 'Novo Pedido').length, [professionalOrders]);
    const newOpportunitiesCount = useMemo(() => {
        if (!currentUser?.serviceCategory) return 0;
        const unlockedIds = new Set(professionalOrders.filter(o => o.professionalId === currentUser.email).map(o => o.id));
        return serviceRequests.filter(req => req.status !== 'Finalizado' && req.serviceCategory === currentUser.serviceCategory && !unlockedIds.has(req.id)).length;
    }, [serviceRequests, currentUser, professionalOrders]);

    const viewProfessionalProfile = (service: Service) => { setViewedService(service); navigate('professionalProfile'); };
    const initiateServiceRequest = (serviceName: string, categoryName: string) => { setRequestServiceContext({ category: categoryName, service: serviceName }); navigate('requestService'); };
    const clearRequestServiceContext = () => setRequestServiceContext(null);
    const viewCategory = (categoryTitle: string) => { setViewedCategory(categoryTitle); navigate('categoryView'); };
    const openReviewModal = (context: ReviewContextType) => setReviewContext(context);
    const closeReviewModal = () => setReviewContext(null);
    const openPaymentModal = (pkg: CreditPackage) => setPaymentContext(pkg);
    const closePaymentModal = () => setPaymentContext(null);
    const openChangePasswordModal = () => setChangePasswordModalOpen(true);
    const closeChangePasswordModal = () => setChangePasswordModalOpen(false);
    const openForgotPasswordModal = () => setForgotPasswordModalOpen(true);
    const closeForgotPasswordModal = () => setForgotPasswordModalOpen(false);

    const submitReview = (serviceName: string, orderId: number, review: Review) => {
        setAllServiceCategories(prev => prev.map(cat => ({
            ...cat,
            services: cat.services.map(s => {
                if (s.name !== serviceName) return s;
                const reviews = [...(s.reviews || []), review];
                return { ...s, reviews, reviewCount: reviews.length, rating: reviews.reduce((a,b)=>a+b.rating,0)/reviews.length };
            })
        })));
        setReviewedOrderIds(prev => [...prev, orderId]);
    };

    const verifyEmail = (email: string) => { updateUserProfile(email, { isEmailVerified: true }); showToast('E-mail verificado!', 'success'); };
    const submitDocumentForVerification = (email: string, url: string) => { updateUserProfile(email, { documentUrl: url, verificationStatus: 'Pending' }); };
    const approveVerification = (email: string) => { updateUserProfile(email, { verificationStatus: 'Verified', isVerified: true }); };
    const rejectVerification = (email: string) => { updateUserProfile(email, { verificationStatus: 'Rejected' }); };

    const addSupportMessage = (text: string) => {
        if (!currentUser) return;
        const msg: SupportMessage = { sender: 'user', text, timestamp: Date.now() };
        setSupportTickets(prev => {
            const idx = prev.findIndex(t => t.userId === currentUser.email && t.status === 'Aberto');
            if (idx > -1) {
                const copy = [...prev];
                copy[idx].messages.push(msg);
                return copy;
            }
            return [{ id: Date.now(), userId: currentUser.email, userName: currentUser.name, status: 'Aberto', timestamp: Date.now(), messages: [msg] }, ...prev];
        });
    };

    const replyToSupportTicket = (id: number, text: string) => {
        setSupportTickets(prev => prev.map(t => t.id === id ? { ...t, messages: [...t.messages, { sender: 'support', text, timestamp: Date.now() }] } : t));
    };

    const updateSupportTicketStatus = (id: number, status: 'Aberto' | 'Fechado') => {
        setSupportTickets(prev => prev.map(t => t.id === id ? { ...t, status } : t));
    };

    return (
        <AppContext.Provider value={{ 
            currentUser, isLoggedIn, login, logout, setUserCredits, activeView, navigate, updateUserProfile,
            adminChangeUserPassword,
            viewedService, viewProfessionalProfile, reviewContext, openReviewModal, closeReviewModal, 
            submitReview, reviewedOrderIds, allServiceCategories, setAllServiceCategories,
            paymentContext, openPaymentModal, closePaymentModal,
            isChangePasswordModalOpen, openChangePasswordModal, closeChangePasswordModal,
            isForgotPasswordModalOpen, openForgotPasswordModal, closeForgotPasswordModal,
            viewedCategory, viewCategory, toast, showToast,
            clientOrders, setClientOrders, professionalOrders, setProfessionalOrders, newOrdersCount, newOpportunitiesCount,
            serviceRequests, setServiceRequests, addServiceRequest,
            requestServiceContext, initiateServiceRequest, clearRequestServiceContext,
            allUsers, setAllUsers, supportTickets, addSupportMessage, replyToSupportTicket, updateSupportTicketStatus,
            transactions, verifyEmail, submitDocumentForVerification, approveVerification, rejectVerification,
            completeServiceByProfessional, finalizeServiceByClient,
            themeColor: customizationSettings.themeColor, setThemeColor,
            heroContent: customizationSettings.heroContent, setHeroContent,
            appName: customizationSettings.appName, setAppName,
            appLogo: customizationSettings.appLogo, setAppLogo,
            fontFamily: customizationSettings.fontFamily, setFontFamily,
            paymentGateway: customizationSettings.paymentGateway, setPaymentGateway,
            paymentConfig: customizationSettings.paymentConfig, setPaymentConfig,
            abTestConfig: customizationSettings.abTestConfig, startABTest: (v) => {}, endABTest: () => {},
            assignedHeroContent: customizationSettings.heroContent,
            pricingTiers: customizationSettings.pricingTiers, setPricingTiers
        }}>
            {children}
        </AppContext.Provider>
    );
};

export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext must be used within AppContextProvider');
    return context;
};

import React, { createContext, useState, useContext, useMemo, useEffect } from 'react';
import { Conversation, ChatMessage, User } from '../types';
import { initialConversations } from '../data/mockData';
import { useAppContext } from './AppContext';
import { secureStorage } from '../utils/secureStorage';

interface ChatContextType {
    conversations: Conversation[];
    activeConversationId: string | null;
    setActiveConversationId: (id: string | null) => void;
    startChat: (otherUser: User) => void;
    sendMessage: (text: string) => void;
    unreadMessagesCount: number;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

const CHAT_STORAGE_KEY = 'chamaai_conversations_v27';

export const ChatContextProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { currentUser, navigate } = useAppContext();

    // Inicializa do Storage ou Mock
    const [conversations, setConversations] = useState<Conversation[]>(() => {
        return secureStorage.getItem(CHAT_STORAGE_KEY) || initialConversations;
    });

    const [activeConversationId, setActiveConversationId] = useState<string | null>(null);

    // Salva sempre que as conversas mudarem
    useEffect(() => {
        secureStorage.setItem(CHAT_STORAGE_KEY, conversations);
    }, [conversations]);

    const startChat = (otherUser: User) => {
        if (!currentUser) {
            navigate('login');
            return;
        }

        // Correção: ID consistente ordenando os e-mails alfabeticamente
        const conversationId = [currentUser.email.toLowerCase(), otherUser.email.toLowerCase()].sort().join('_');
        const existingConversation = conversations.find(c => c.id === conversationId);

        if (!existingConversation) {
            const newConversation: Conversation = {
                id: conversationId,
                participants: {
                    [currentUser.email.toLowerCase()]: currentUser,
                    [otherUser.email.toLowerCase()]: otherUser
                },
                messages: [],
            };
            setConversations(prev => [...prev, newConversation]);
        }

        setActiveConversationId(conversationId);
        navigate('chat');
    };

    const sendMessage = (text: string) => {
        if (!currentUser || !activeConversationId) return;

        const convIdx = conversations.findIndex(c => c.id === activeConversationId);
        if (convIdx === -1) return;

        const newMessage: ChatMessage = {
            senderEmail: currentUser.email,
            text,
            timestamp: Date.now(),
        };

        const updatedConversations = [...conversations];
        const currentConv = { ...updatedConversations[convIdx] };
        currentConv.messages = [...currentConv.messages, newMessage];
        updatedConversations[convIdx] = currentConv;

        setConversations(updatedConversations);

        // Simulador de Resposta Automática do Profissional (apenas para Demo)
        const otherUserEmail = Object.keys(currentConv.participants).find(email => email !== currentUser.email.toLowerCase());
        if (otherUserEmail && currentConv.participants[otherUserEmail].userType === 'professional') {
            setTimeout(() => {
                const replyMessage: ChatMessage = {
                    senderEmail: otherUserEmail,
                    text: "Olá! Acabei de receber sua mensagem. Como posso te ajudar com este serviço?",
                    timestamp: Date.now(),
                };
                setConversations(prev => prev.map(c => 
                    c.id === activeConversationId ? { ...c, messages: [...c.messages, replyMessage] } : c
                ));
            }, 1000);
        }
    };

    const unreadMessagesCount = useMemo(() => currentUser
        ? conversations.reduce((count, conv) => {
            if (Object.keys(conv.participants).includes(currentUser.email.toLowerCase())) {
                const lastMessage = conv.messages[conv.messages.length - 1];
                if (lastMessage && lastMessage.senderEmail !== currentUser.email) {
                    return count + 1;
                }
            }
            return count;
        }, 0)
        : 0, [conversations, currentUser]);


    return (
        <ChatContext.Provider value={{ conversations, activeConversationId, setActiveConversationId, startChat, sendMessage, unreadMessagesCount }}>
            {children}
        </ChatContext.Provider>
    );
};

export const useChatContext = () => {
    const context = useContext(ChatContext);
    if (context === undefined) {
        throw new Error('useChatContext must be used within a ChatContextProvider');
    }
    return context;
};

