import React from 'react';
import { BriefcaseIcon, CheckCircleIcon, ClockIcon, ChatAlt2Icon, CoinIcon, ChatBubbleLeftRightIcon, StarIcon, PlusCircleIcon, SparklesIcon } from './Icons';
import { Service, User } from '../types';
import { useAppContext } from '../contexts/AppContext';
import { useChatContext } from '../contexts/ChatContext';

type Order = {
  id: number;
  service: string;
  date: string;
  // FIX: Updated Order status type here as well to maintain consistency.
  status: 'Em Andamento' | 'Agendado' | 'Concluído pelo Profissional' | 'Finalizado' | 'Contato Liberado' | 'Novo Pedido' | 'Aguardando Profissionais';
  otherParty: User;
  isLocked?: boolean;
}

const getStatusChip = (status: Order['status'], themeColor: string) => {
  const common = "flex items-center text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full ios-shadow backdrop-blur-md border border-white/40";
  switch (status) {
    case 'Em Andamento':
    case 'Agendado':
      return <div className={`${common} text-yellow-600 bg-yellow-100/50`}><ClockIcon className="w-3 h-3 mr-1" />{status}</div>;
    case 'Finalizado':
      return <div className={`${common} text-green-600 bg-green-100/50`}><CheckCircleIcon className="w-3 h-3 mr-1" />{status}</div>;
    case 'Concluído pelo Profissional':
      return <div className={`${common} text-blue-600 bg-blue-100/50`}><SparklesIcon className="w-3 h-3 mr-1" />Aguardando Confirmação</div>;
    // FIX: Added 'Aguardando Profissionais' to the chip status display.
    case 'Aguardando Profissionais':
    case 'Contato Liberado':
    case 'Novo Pedido':
      return <div className={`${common} text-${themeColor}-600 bg-${themeColor}-100/50`}><ChatAlt2Icon className="w-3 h-3 mr-1" />{status}</div>;
    default:
      return null;
  }
};


const OrderCard: React.FC<{ order: Order; isClient: boolean; onAction: (action: string, payload?: any) => void }> = ({ order, isClient, onAction }) => {
    const { themeColor } = useAppContext();
    const { id, service, otherParty, date, status, isLocked } = order;

    return (
        <li className="glass-card rounded-[2rem] p-6 ios-shadow transition-all duration-300 hover:scale-[1.01] border border-white/50 mb-4 list-none">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex-grow">
                    <div className="flex items-center gap-4">
                        <div className="relative">
                            <img src={otherParty.avatar || `https://i.pravatar.cc/150?u=${otherParty.email}`} alt={otherParty.name} className="w-16 h-16 rounded-2xl object-cover ring-2 ring-white/50 shadow-sm" />
                            {!isLocked && <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-green-500 rounded-full border-2 border-white flex items-center justify-center"><div className="w-2 h-2 bg-white rounded-full animate-pulse"></div></div>}
                        </div>
                        <div>
                            <p className={`text-xl font-extrabold text-slate-900 tracking-tight`}>{service}</p>
                            <p className="text-sm font-medium text-slate-500">
                                {isClient ? `Profissional: ` : `Cliente: `}
                                <span className="text-slate-800">{isLocked ? otherParty.name.split(' ')[0] : otherParty.name}</span>
                            </p>
                            <p className="text-[10px] font-bold text-slate-400 uppercase mt-1 tracking-widest">{date}</p>
                        </div>
                    </div>
                </div>
                <div className="w-full sm:w-auto flex flex-col sm:items-end gap-3">
                    <div className="self-start sm:self-end">{getStatusChip(status, themeColor)}</div>
                    <div className="flex items-center flex-wrap gap-2 mt-2">
                        {/* Ação Cliente: Finalizar */}
                        {isClient && status === 'Concluído pelo Profissional' && (
                            <button onClick={() => onAction('finalize', id)}
                                className={`bg-gradient-to-r from-green-500 to-emerald-600 text-white font-bold text-xs py-2.5 px-5 rounded-full ios-shadow transition-all hover:scale-105 active:scale-95 flex items-center gap-1.5`}>
                               <CheckCircleIcon className="w-4 h-4" /> Finalizar Serviço
                            </button>
                        )}
                        {/* Ação Cliente: Avaliar */}
                        {isClient && status === 'Finalizado' && (
                            <button onClick={() => onAction('review', { service, orderId: id })}
                                className="bg-white/80 backdrop-blur-sm text-yellow-600 border border-yellow-100 font-bold text-xs py-2.5 px-5 rounded-full ios-shadow transition-all hover:bg-yellow-50 flex items-center gap-1.5">
                               <StarIcon className="w-4 h-4" /> Avaliar
                            </button>
                        )}
                        {/* Chat */}
                        {!isLocked && status !== 'Finalizado' && (
                           <button onClick={() => onAction('chat', otherParty)} className={`bg-white/80 backdrop-blur-sm text-${themeColor}-600 border border-${themeColor}-100 font-bold text-xs py-2.5 px-5 rounded-full ios-shadow transition-all hover:bg-${themeColor}-50 flex items-center gap-1.5`}>
                             <ChatBubbleLeftRightIcon className="w-4 h-4" /> Conversar
                           </button>
                        )}
                        {/* Ação Profissional: Encerrar */}
                        {!isClient && !isLocked && status !== 'Finalizado' && status !== 'Concluído pelo Profissional' && (
                            <button onClick={() => onAction('complete', id)} className={`bg-slate-900 text-white font-bold text-xs py-2.5 px-5 rounded-full ios-shadow transition-all hover:scale-105 active:scale-95`}>
                                Marcar como Concluído
                            </button>
                        )}
                        {/* Desbloqueio */}
                        {isLocked && (
                          <button onClick={() => onAction('unlock', id)} className={`bg-blue-600 text-white font-bold text-xs py-2.5 px-5 rounded-full ios-shadow transition-all hover:scale-105 active:scale-95 flex items-center gap-1.5`}>
                            <CoinIcon className="w-4 h-4" />
                            Liberar Contato (1 crédito)
                          </button>
                        )}
                    </div>
                </div>
            </div>
        </li>
    );
};


const Orders: React.FC = () => {
  const { 
      currentUser, setUserCredits, navigate, openReviewModal, reviewedOrderIds, 
      themeColor, allServiceCategories, clientOrders, professionalOrders, 
      setProfessionalOrders, completeServiceByProfessional, finalizeServiceByClient
  } = useAppContext();
  const { startChat } = useChatContext();

  if (!currentUser) return null;

  const isClient = currentUser.userType === 'client';

  const findServiceByName = (name: string): Service | null => {
      for (const category of allServiceCategories) {
          const service = category.services.find(s => s.name === name);
          if (service) return service;
      }
      return null;
  };

  const handleAction = (action: string, payload: any) => {
    switch(action) {
      case 'unlock': {
        const UNLOCK_COST = 1;
        if (currentUser.credits === undefined || currentUser.credits < UNLOCK_COST) {
          alert('Saldo insuficiente.');
          navigate('credits');
          return;
        }
        setUserCredits((currentUser.credits ?? 0) - UNLOCK_COST);
        setProfessionalOrders(prev => prev.map(o => o.id === payload ? { ...o, locked: false, status: 'Contato Liberado' } : o));
        break;
      }
      case 'complete': {
        if (window.confirm('Confirmar conclusão do trabalho? O cliente precisará validar para finalizar.')) {
          completeServiceByProfessional(payload);
        }
        break;
      }
      case 'finalize': {
        if (window.confirm('Confirmar finalização? O pedido sairá do marketplace.')) {
          finalizeServiceByClient(payload);
        }
        break;
      }
      case 'review': {
        const serviceDetails = findServiceByName(payload.service);
        if (serviceDetails && !reviewedOrderIds.includes(payload.orderId)) {
          openReviewModal({ service: serviceDetails, orderId: payload.orderId });
        }
        break;
      }
      case 'chat': {
        startChat(payload);
        break;
      }
      default:
        break;
    }
  };

  const orders: Order[] = isClient 
    ? clientOrders
        .filter(o => o.clientId === currentUser.email)
        .map(o => ({ ...o, otherParty: o.professional }))
    : professionalOrders
        .filter(o => o.professionalId === currentUser.email)
        .map(o => ({ ...o, otherParty: o.client, isLocked: o.locked }));

  return (
    <div className="min-h-full pb-32 pt-6 px-4 sm:px-6 lg:px-8">
      <header className="max-w-5xl mx-auto flex items-center justify-between mb-10">
        <div>
            <h1 className="text-sm font-bold uppercase tracking-[0.2em] text-slate-400">Gerenciador</h1>
            <p className="text-3xl font-black text-slate-900 tracking-tight">{isClient ? 'Meus Pedidos' : 'Meus Serviços'}</p>
        </div>
        {isClient ? (
            <button onClick={() => navigate('requestService')} className={`h-12 w-12 flex items-center justify-center glass-card rounded-2xl ios-shadow transition-transform active:scale-90 text-${themeColor}-600`}>
                <PlusCircleIcon className="w-6 h-6" />
            </button>
        ) : (
            <div onClick={() => navigate('credits')} className="glass-card px-4 py-2 rounded-2xl ios-shadow cursor-pointer flex items-center gap-2 group">
                <CoinIcon className="w-5 h-5 text-yellow-500 group-hover:rotate-12 transition-transform" />
                <span className="font-bold text-slate-800">{currentUser.credits ?? 0}</span>
            </div>
        )}
      </header>

      <main className="max-w-5xl mx-auto">
        {orders.length > 0 ? (
          <ul className="space-y-4 p-0">
            {orders.map(order => (
                <OrderCard 
                    key={order.id} 
                    order={order} 
                    isClient={isClient}
                    onAction={handleAction}
                />
            ))}
          </ul>
        ) : (
          <div className="glass-card rounded-[3rem] p-12 text-center ios-shadow border border-white/50">
            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-6">
                <BriefcaseIcon className="h-10 w-10 text-slate-300" />
            </div>
            <h3 className="text-xl font-bold text-slate-800">Nenhum serviço aqui</h3>
            <p className="text-sm text-slate-400 mt-2 max-w-xs mx-auto">
              {isClient ? 'Você ainda não fez nenhum pedido. Comece agora!' : 'Aguardando novas oportunidades no Marketplace.'}
            </p>
            <button 
                onClick={() => navigate(isClient ? 'home' : 'marketplace')} 
                className={`mt-8 bg-${themeColor}-600 text-white font-bold px-8 py-3 rounded-full ios-shadow transition-all active:scale-95`}
            >
                {isClient ? 'Explorar Categorias' : 'Ir para Marketplace'}
            </button>
          </div>
        )}
      </main>
    </div>
  );
};

