import React, { useState, useRef, useEffect } from 'react';
import { User, Conversation } from '../types';
import { ArrowLeftIcon, WhatsAppIcon, PhoneIcon } from './Icons';
import { useAppContext } from '../contexts/AppContext';
import { useChatContext } from '../contexts/ChatContext';

const ConversationList: React.FC = () => {
    const { currentUser, themeColor } = useAppContext();
    const { conversations, setActiveConversationId, activeConversationId } = useChatContext();

    const userConversations = conversations.filter(c => currentUser && Object.keys(c.participants).includes(currentUser.email.toLowerCase()));

    return (
        <div className="h-full flex flex-col">
            <header className="p-4 border-b border-slate-200 flex-shrink-0">
                <h1 className="text-xl font-bold text-slate-800 tracking-tight">Mensagens</h1>
            </header>
            <div className="flex-grow overflow-y-auto">
                {userConversations.length === 0 ? (
                    <div className="text-center p-12 text-slate-400">
                        <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
                        </div>
                        <p className="font-bold">Sem conversas</p>
                        <p className="text-xs mt-1">Seus chats aparecerão aqui após o desbloqueio.</p>
                    </div>
                ) : (
                    <ul className="divide-y divide-slate-100">
                        {userConversations.map(conv => {
                            if (!currentUser) return null;
                            const otherUserEmail = Object.keys(conv.participants).find(email => email !== currentUser.email.toLowerCase());
                            if (!otherUserEmail) return null;
                            const otherUser = conv.participants[otherUserEmail];
                            const lastMessage = conv.messages[conv.messages.length - 1];
                            const isActive = conv.id === activeConversationId;

                            return (
                                <li key={conv.id} onClick={() => setActiveConversationId(conv.id)} className={`p-4 cursor-pointer flex items-center space-x-4 transition-all duration-200 ${isActive ? `bg-${themeColor}-50/80` : 'hover:bg-slate-50'}`}>
                                    <div className="relative flex-shrink-0">
                                        <img className="h-12 w-12 rounded-2xl object-cover ring-2 ring-white shadow-sm" src={otherUser.avatar || `https://i.pravatar.cc/150?u=${otherUser.email}`} alt={otherUser.name} />
                                        {isActive && <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 rounded-full border-2 border-white"></div>}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex justify-between items-baseline">
                                            <p className={`text-sm font-bold truncate ${isActive ? `text-${themeColor}-700` : 'text-slate-900'}`}>{otherUser.name}</p>
                                        </div>
                                        <p className="text-xs text-slate-400 truncate mt-0.5">{lastMessage ? `${lastMessage.senderEmail === currentUser.email ? 'Você: ' : ''}${lastMessage.text}` : 'Clique para iniciar'}</p>
                                    </div>
                                </li>
                            )
                        })}
                    </ul>
                )}
            </div>
        </div>
    )
};

const ChatWindow: React.FC = () => {
    const { currentUser, themeColor } = useAppContext();
    const { conversations, activeConversationId, setActiveConversationId, sendMessage, isOtherTyping } = useChatContext();
    const [inputText, setInputText] = useState('');
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const activeConversation = conversations.find(c => c.id === activeConversationId);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [activeConversation?.messages, isOtherTyping]);

    if (!activeConversation || !currentUser) {
        return <div className="flex items-center justify-center h-full text-slate-400">Selecione uma conversa</div>;
    }

    const otherUser = (Object.values(activeConversation.participants) as User[]).find(p => p.email.toLowerCase() !== currentUser.email.toLowerCase());
    if (!otherUser) return null;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (inputText.trim()) {
            sendMessage(inputText);
            setInputText('');
        }
    };

    const handleWhatsApp = () => {
        if (!otherUser.phoneNumber) {
            alert("Este usuário não cadastrou um número de telefone.");
            return;
        }
        const cleanNumber = otherUser.phoneNumber.replace(/\D/g, '');
        window.open(`https://wa.me/55${cleanNumber}`, '_blank');
    };

    return (
        <div className="flex flex-col h-full bg-slate-50">
            <header className="flex items-center justify-between p-3 border-b border-slate-200 bg-white/80 backdrop-blur-md sticky top-0 z-10">
                <div className="flex items-center">
                    <button onClick={() => setActiveConversationId(null)} className="p-2 mr-2 text-slate-600 hover:bg-slate-100 rounded-full md:hidden">
                        <ArrowLeftIcon className="w-6 h-6" />
                    </button>
                    <img className="h-10 w-10 rounded-xl mr-3 object-cover shadow-sm ring-1 ring-slate-100" src={otherUser.avatar || `https://i.pravatar.cc/150?u=${otherUser.email}`} alt={otherUser.name} />
                    <div>
                        <h2 className="text-sm font-bold text-slate-800 leading-none">{otherUser.name}</h2>
                        <span className="text-[10px] text-green-500 font-bold uppercase tracking-wider">Online agora</span>
                    </div>
                </div>
                <button 
                    onClick={handleWhatsApp}
                    className="bg-green-500 text-white p-2.5 rounded-full shadow-lg hover:bg-green-600 transition-all active:scale-95 flex items-center gap-2 px-4"
                >
                    <WhatsAppIcon className="w-5 h-5" />
