const Marketplace: React.FC = () => {
    const { currentUser, serviceRequests, unlockService, professionalOrders, themeColor, navigate, allUsers } = useAppContext();
    const [searchTerm, setSearchTerm] = useState('');
    const [unlockingId, setUnlockingId] = useState<number | null>(null);

    if (!currentUser || currentUser.userType !== 'professional') return null;

    const myUnlockedIds = new Set(
        professionalOrders
            .filter(o => o.professionalId === currentUser.email)
            .map(o => o.id)
    );

    const availableRequests = useMemo(() => {
        return serviceRequests
            .filter(req => req.status === 'Aguardando Profissionais' && !myUnlockedIds.has(req.id))
            .filter(req => {
                const searchMatch = searchTerm === '' || 
                                    req.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                                    req.description.toLowerCase().includes(searchTerm.toLowerCase());
                return searchMatch;
            });
    }, [serviceRequests, myUnlockedIds, searchTerm]);

    const handleUnlockContact = (request: ServiceRequest, e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();

        const cost = request.unlockCost;
        const currentCredits = currentUser.credits || 0;

        if (currentCredits < cost) {
            alert(`Saldo insuficiente! Você precisa de ${cost} créditos.`);
            navigate('credits');
            return;
        }

        if (!window.confirm(`Desbloquear contato por ${cost} créditos?`)) return;

        setUnlockingId(request.id);

        setTimeout(() => {
            unlockService(request);
            setUnlockingId(null);
            setTimeout(() => navigate('orders'), 500);
        }, 800);
    };

    return (
        <div className="min-h-full pb-32 pt-6 px-4 sm:px-6 lg:px-8">
            <header className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
                <div>
                    <h1 className="text-sm font-bold uppercase tracking-[0.2em] text-slate-400">Oportunidades</h1>
                    <p className="text-4xl font-black text-slate-900 tracking-tight flex items-center gap-3">
                       Marketplace <SparklesIcon className="w-8 h-8 text-blue-500 animate-pulse" />
                    </p>
                </div>
                <div onClick={() => navigate('credits')} className="glass-card px-6 py-3 rounded-2xl ios-shadow cursor-pointer flex items-center gap-3 group border border-white/50 transition-all hover:bg-white/90">
                    <div className="bg-yellow-100 p-2 rounded-xl group-hover:scale-110 transition-transform">
                        <CoinIcon className="w-5 h-5 text-yellow-600" />
                    </div>
                    <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Seu Saldo</p>
                        <p className="font-black text-slate-800 text-lg leading-none">{currentUser.credits ?? 0}</p>
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto">
                <div className="mb-10 flex flex-col md:flex-row gap-4 p-2">
                    <div className="relative flex-grow">
                        <div className="absolute inset-y-0 left-5 flex items-center pointer-events-none">
                            <SearchIcon className="h-5 w-5 text-slate-400" />
                        </div>
                        <input
                            type="text"
                            placeholder="Buscar pedidos no Marketplace..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className={`w-full pl-14 pr-6 py-4 glass-card border border-white/60 rounded-3xl text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all font-medium ios-shadow placeholder:text-slate-300`}
                        />
                    </div>
                </div>

                {availableRequests.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {availableRequests.map(request => (
                            <ServiceRequestCard 
                                key={request.id} 
                                request={request} 
                                client={allUsers[request.clientId.toLowerCase()]}
                                onUnlock={handleUnlockContact} 
                                themeColor={themeColor}
                                isUnlocking={unlockingId === request.id}
                            />
                        ))}
                    </div>
                ) : (
                    <div className="glass-card rounded-[3.5rem] py-24 px-8 text-center ios-shadow border border-white/50">
                        <div className="w-24 h-24 bg-slate-100 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 rotate-3">
                            <BuildingStorefrontIcon className="h-12 w-12 text-slate-300" />
                        </div>
                        <h3 className="text-2xl font-black text-slate-800 tracking-tight">Marketplace Limpo</h3>
                        <p className="mt-3 text-slate-400 max-w-sm mx-auto font-medium">
                           Não há novos serviços para o seu perfil agora.
                        </p>
                    </div>
                )}
            </main>
        </div>
    );
};

export default Marketplace;

