import React, { createContext, useState, useContext, useMemo, useEffect } from 'react';
import { User, Service, Review, ServiceCategory, HeroContent, CreditPackage, ServiceRequest, ClientOrder, ProfessionalOrder, ABTestConfig, PricingTiers, Users, SupportTicket, SupportMessage, Transaction, PaymentConfig } from '../types';
import { servicesData, initialClientOrders, initialProfessionalOrders, initialServiceRequests, allUsers as initialUsers, initialSupportTickets, initialTransactions } from '../data/mockData';
import { secureStorage } from '../utils/secureStorage';
import { parseService } from '../services/parseService';

export type View = 'home' | 'orders' | 'login' | 'profile' | 'credits' | 'chat' | 'professionalProfile' | 'adminPanel' | 'categoryView' | 'marketplace' | 'requestService';

export type ReviewContextType = {
    service: Service;
    orderId: number;
};

type ToastState = {
  message: string;
  type: 'success' | 'error';
  visible: boolean;
};

interface AppContextType {
    currentUser: User | null;
    isLoggedIn: boolean;
    login: (user: User) => void;
    logout: () => void;
    setUserCredits: (newCreditCount: number) => void;
    updateUserProfile: (email: string, updatedProfile: Partial<User>) => void;
    adminChangeUserPassword: (email: string, newPassword: string) => void;
    activeView: View;
    navigate: (view: View) => void;
    viewedService: Service | null;
    viewProfessionalProfile: (service: Service) => void;
    viewedCategory: string | null;
    viewCategory: (categoryTitle: string) => void;
    reviewContext: ReviewContextType | null;
    openReviewModal: (context: ReviewContextType) => void;
    closeReviewModal: () => void;
    submitReview: (serviceName: string, orderId: number, review: Review) => void;
    reviewedOrderIds: number[];
    paymentContext: CreditPackage | null;
    openPaymentModal: (pkg: CreditPackage) => void;
    closePaymentModal: () => void;
    isChangePasswordModalOpen: boolean;
    openChangePasswordModal: () => void;
    closeChangePasswordModal: () => void;
    isForgotPasswordModalOpen: boolean;
    openForgotPasswordModal: () => void;
    closeForgotPasswordModal: () => void;
    themeColor: string;
    setThemeColor: (color: string) => void;
    heroContent: HeroContent;
    setHeroContent: (content: HeroContent) => void;
    allServiceCategories: ServiceCategory[];
    setAllServiceCategories: React.Dispatch<React.SetStateAction<ServiceCategory[]>>;
    appName: string;
    setAppName: (name: string) => void;
    appLogo: string | null;
    setAppLogo: (logo: string | null) => void;
    fontFamily: string;
    setFontFamily: (font: string) => void;
    paymentGateway: string;
    setPaymentGateway: (gateway: string) => void;
    paymentConfig: PaymentConfig;
    setPaymentConfig: (config: PaymentConfig) => void;
    toast: ToastState;
    showToast: (message: string, type: 'success' | 'error') => void;
    abTestConfig: ABTestConfig | null;
    startABTest: (variations: HeroContent[]) => void;
    endABTest: () => void;
    assignedHeroContent: HeroContent;
    clientOrders: ClientOrder[];
    setClientOrders: React.Dispatch<React.SetStateAction<ClientOrder[]>>;
    professionalOrders: ProfessionalOrder[];
    setProfessionalOrders: React.Dispatch<React.SetStateAction<ProfessionalOrder[]>>;
    newOrdersCount: number;
    newOpportunitiesCount: number;
    serviceRequests: ServiceRequest[];
    setServiceRequests: React.Dispatch<React.SetStateAction<ServiceRequest[]>>;
    addServiceRequest: (request: Omit<ServiceRequest, 'id' | 'clientId' | 'status' | 'date' | 'unlockCost'>) => void;
    unlockService: (request: ServiceRequest) => void;
    requestServiceContext: { category: string; service: string } | null;
    initiateServiceRequest: (serviceName: string, categoryName: string) => void;
    clearRequestServiceContext: () => void;
    pricingTiers: PricingTiers;
    setPricingTiers: (tiers: PricingTiers) => void;
    allUsers: Users;
    setAllUsers: React.Dispatch<React.SetStateAction<Users>>;
    supportTickets: SupportTicket[];
    addSupportMessage: (messageText: string) => void;
    replyToSupportTicket: (ticketId: number, replyText: string) => void;
    updateSupportTicketStatus: (ticketId: number, status: 'Aberto' | 'Fechado') => void;
    transactions: Transaction[];
    addServiceCategory: (title: string) => void;
    updateServiceCategory: (oldTitle: string, newTitle: string) => void;
    deleteServiceCategory: (title: string) => void;
    addService: (categoryTitle: string, serviceData: Omit<Service, 'rating' | 'reviewCount' | 'reviews'>) => void;
    updateService: (categoryTitle: string, serviceName: string, updatedServiceData: Partial<Service>) => void;
    deleteService: (categoryTitle: string, serviceName: string) => void;
    verifyEmail: (email: string) => void;
    submitDocumentForVerification: (email: string, documentUrl: string) => void;
    approveVerification: (email: string) => void;
    rejectVerification: (email: string) => void;
    completeServiceByProfessional: (orderId: number) => void;
    finalizeServiceByClient: (orderId: number) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const STORAGE_KEYS = {
    CURRENT_USER: 'chamaai_currentUser_v31',
    CUSTOMIZATION: 'chamaai_custom_v31',
};

export const AppContextProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [allUsers, setAllUsers] = useState<Users>(initialUsers);
    const [currentUser, setCurrentUser] = useState<User | null>(() => secureStorage.getItem(STORAGE_KEYS.CURRENT_USER) || null);
    const [clientOrders, setClientOrders] = useState<ClientOrder[]>(initialClientOrders);
    const [professionalOrders, setProfessionalOrders] = useState<ProfessionalOrder[]>(initialProfessionalOrders);
    const [serviceRequests, setServiceRequests] = useState<ServiceRequest[]>(initialServiceRequests);

    const [customizationSettings, setCustomizationSettings] = useState(() => secureStorage.getItem(STORAGE_KEYS.CUSTOMIZATION) || {
        themeColor: 'sky',
        fontFamily: 'Inter',
        appName: 'Chama aí',
        appLogo: null,
        heroContent: { title: 'A plataforma completa para', highlight: 'seu projeto', subtitle: 'Encontre o talento que você precisa para decolar.' },
        pricingTiers: { 'Baixa': 2, 'Média': 5, 'Alta': 10 },
    });

    const [abTestConfig, setAbTestConfig] = useState<ABTestConfig | null>(null);

    // Sync inicial com Back4App
    useEffect(() => {
        const loadRequests = async () => {
            try {
                const cloudRequests = await parseService.getServiceRequests();
                if (cloudRequests && cloudRequests.length > 0) setServiceRequests(cloudRequests);
            } catch (e) { console.warn("Parse Load Error", e); }
        };
        loadRequests();
    }, []);

    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.CURRENT_USER, currentUser); }, [currentUser]);
    useEffect(() => { secureStorage.setItem(STORAGE_KEYS.CUSTOMIZATION, customizationSettings); }, [customizationSettings]);

    const login = async (user: User) => {
        const emailKey = user.email.toLowerCase();
        try {
            const dbUser = await parseService.getUserByEmail(user.email);
            if (dbUser) {
                const userData = { ...dbUser.attributes };
                setCurrentUser(userData as User);
                setAllUsers(prev => ({ ...prev, [emailKey]: userData as User }));
            } else {
                await parseService.saveUser(user);
                setCurrentUser(user);
                setAllUsers(prev => ({ ...prev, [emailKey]: user }));
            }
        } catch (e) {
            setCurrentUser(user);
        }
        setActiveView(user.email === 'conectechserver@gmail.com' ? 'adminPanel' : 'home');
    };

    const logout = () => { setCurrentUser(null); setActiveView('home'); };

    const setUserCredits = async (newCreditCount: number) => {
        if (currentUser) {
            const updatedUser = { ...currentUser, credits: newCreditCount };
            setCurrentUser(updatedUser);
            await parseService.updateUser(currentUser.email, { credits: newCreditCount });
        }
    };

    const updateUserProfile = async (email: string, updatedProfile: Partial<User>) => {
        if (currentUser?.email === email) setCurrentUser(prev => prev ? { ...prev, ...updatedProfile } : null);
        await parseService.updateUser(email, updatedProfile);
    };

    const [activeView, setActiveView] = useState<View>('home');
    const navigate = (view: View) => {
        if (['profile', 'orders', 'credits', 'chat', 'requestService'].includes(view) && !currentUser) {
            setActiveView('login');
        } else {
            setActiveView(view);
        }
    };

    const [viewedService, setViewedService] = useState<Service | null>(null);
    const [viewedCategory, setViewedCategory] = useState<string | null>(null);
    const [reviewContext, setReviewContext] = useState<ReviewContextType | null>(null);
    const [reviewedOrderIds, setReviewedOrderIds] = useState<number[]>([]);
    const [paymentContext, setPaymentContext] = useState<CreditPackage | null>(null);
    const [isChangePasswordModalOpen, setChangePasswordModalOpen] = useState(false);
    const [isForgotPasswordModalOpen, setForgotPasswordModalOpen] = useState(false);

    const [allServiceCategories, setAllServiceCategories] = useState<ServiceCategory[]>(servicesData);
    const [supportTickets, setSupportTickets] = useState<SupportTicket[]>(initialSupportTickets);
    const [transactions, setTransactions] = useState<Transaction[]>(initialTransactions);
    const [toast, setToast] = useState<ToastState>({ message: '', type: 'success', visible: false });
    const [requestServiceContext, setRequestServiceContext] = useState<{ category: string; service: string } | null>(null);

    const showToast = (message: string, type: 'success' | 'error') => {
        setToast({ message, type, visible: true });
        setTimeout(() => setToast(prev => ({ ...prev, visible: false })), 3000);
    };

    const addServiceRequest = async (request: Omit<ServiceRequest, 'id' | 'clientId' | 'status' | 'date' | 'unlockCost'>) => {
        if (!currentUser) return;
        const service = allServiceCategories.flatMap(c => c.services).find(s => s.name === request.serviceName);
        const cost = customizationSettings.pricingTiers[service?.complexity || 'Média'] || 2; 

        const newRequest: any = {
            ...request,
            clientId: currentUser.email,
            status: 'Aguardando Profissionais',
            date: new Date().toLocaleDateString('pt-BR'),
            unlockCost: cost,
            customId: Date.now().toString()
        };

        try {
            const saved = await parseService.createServiceRequest(newRequest);
            const typedRequest: ServiceRequest = { ...newRequest, id: saved.id };
            setServiceRequests(prev => [typedRequest, ...prev]);

            const newClientOrder: ClientOrder = {
                id: Date.now(),
                service: typedRequest.title,
                date: typedRequest.date,
                status: 'Aguardando Profissionais',
                clientId: currentUser.email,
                professional: { name: 'Sistema', email: 'pending@system.com', userType: 'professional' }
            };
            setClientOrders(prev => [newClientOrder, ...prev]);
            navigate('orders');
            showToast('Solicitação publicada!', 'success');
        } catch (e) {
            showToast('Erro ao salvar.', 'error');
        }
    };

    const unlockService = async (request: ServiceRequest) => {
        if (!currentUser || currentUser.userType !== 'professional') return;
        const cost = request.unlockCost;
        const currentCredits = currentUser.credits || 0;

        await setUserCredits(currentCredits - cost);
        await parseService.updateServiceRequestStatus(request.id.toString(), 'Em Andamento');

        const clientData = allUsers[request.clientId.toLowerCase()] || { name: 'Cliente', email: request.clientId, userType: 'client' };
        const newProfOrder: ProfessionalOrder = {
            id: Date.now(),
            service: request.title,
            client: clientData as User,
            date: new Date().toLocaleDateString('pt-BR'),
            status: 'Em Andamento',
            locked: false,
            professionalId: currentUser.email
        };
        setProfessionalOrders(prev => [newProfOrder, ...prev]);
        showToast("Contato desbloqueado!", "success");
    };

    const isLoggedIn = !!currentUser;
    const viewProfessionalProfile = (service: Service) => { setViewedService(service); navigate('professionalProfile'); };
    const openReviewModal = (context: ReviewContextType) => { setReviewContext(context); };
    const closeReviewModal = () => { setReviewContext(null); };
    const submitReview = (serviceName: string, orderId: number, review: Review) => {
        setAllServiceCategories(prev => prev.map(cat => ({
            ...cat,
            services: cat.services.map(s => s.name === serviceName ? { 
                ...s, 
                reviews: [review, ...s.reviews], 
                rating: (s.rating * s.reviewCount + review.rating) / (s.reviewCount + 1), 
                reviewCount: s.reviewCount + 1 
            } : s)
        })));
        setReviewedOrderIds(prev => [...prev, orderId]);
        showToast('Avaliação enviada!', 'success');
    };

    const openPaymentModal = (pkg: CreditPackage) => { setPaymentContext(pkg); };
    const closePaymentModal = () => { setPaymentContext(null); };
    const openChangePasswordModal = () => setChangePasswordModalOpen(true);
    const closeChangePasswordModal = () => setChangePasswordModalOpen(false);
    const openForgotPasswordModal = () => setForgotPasswordModalOpen(true);
    const closeForgotPasswordModal = () => setForgotPasswordModalOpen(false);
    const viewCategory = (categoryTitle: string) => { setViewedCategory(categoryTitle); navigate('categoryView'); };
    const initiateServiceRequest = (serviceName: string, categoryName: string) => { setRequestServiceContext({ service: serviceName, category: categoryName }); navigate('requestService'); };
    const clearRequestServiceContext = () => { setRequestServiceContext(null); };
    const adminChangeUserPassword = (email: string, newPassword: string) => { showToast(`Senha de ${email} alterada!`, 'success'); };

    // FIX: assignedHeroContent must be provided in the value
    const assignedHeroContent = customizationSettings.heroContent;

    return (
        <AppContext.Provider value={{ 
            currentUser, isLoggedIn, login, logout, setUserCredits, activeView, navigate, updateUserProfile,
            viewedService, viewProfessionalProfile, reviewContext, openReviewModal, closeReviewModal, 
            submitReview, reviewedOrderIds, allServiceCategories, setAllServiceCategories,
            paymentContext, openPaymentModal, closePaymentModal,
            isChangePasswordModalOpen, openChangePasswordModal, closeChangePasswordModal,
            isForgotPasswordModalOpen, openForgotPasswordModal, closeForgotPasswordModal,
            viewedCategory, viewCategory, toast, showToast,
            clientOrders, setClientOrders, professionalOrders, setProfessionalOrders, 
            newOrdersCount: professionalOrders.filter(o => o.status === 'Novo Pedido').length, 
            newOpportunitiesCount: serviceRequests.filter(r => r.status === 'Aguardando Profissionais').length,
            serviceRequests, setServiceRequests, addServiceRequest, unlockService,
            requestServiceContext, initiateServiceRequest, clearRequestServiceContext,
            allUsers, setAllUsers, supportTickets, transactions, 
            adminChangeUserPassword, abTestConfig, assignedHeroContent,
            verifyEmail: (e) => updateUserProfile(e, { isEmailVerified: true }),
            completeServiceByProfessional: (id) => showToast('Concluído!', 'success'),
            finalizeServiceByClient: (id) => showToast('Finalizado!', 'success'),
            themeColor: customizationSettings.themeColor, setThemeColor: (c) => {},
            heroContent: customizationSettings.heroContent, setHeroContent: (h) => {},
            appName: customizationSettings.appName, setAppName: (n) => {},
            appLogo: customizationSettings.appLogo, setAppLogo: (l) => {},
            fontFamily: customizationSettings.fontFamily, setFontFamily: (f) => {},
            pricingTiers: customizationSettings.pricingTiers, setPricingTiers: (t) => {}
        } as any}>
            {children}
        </AppContext.Provider>
    );
};

export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext must be used within AppContextProvider');
    return context;
};

import React, { useState, useMemo } from 'react';
import { SearchIcon } from './Icons';
import ServiceGrid from './ServiceGrid';
import GroundingSearch from './GroundingSearch';
import { searchWithGrounding } from '../services/geminiService';
import { GroundingChunk, Service, ServiceCategory } from '../types';
import { useAppContext } from '../contexts/AppContext';
import ServiceCardSkeleton from './ServiceCardSkeleton';

const Home: React.FC = () => {
  const { navigate, isLoggedIn, currentUser, themeColor, assignedHeroContent, allServiceCategories } = useAppContext();
  const [searchTerm, setSearchTerm] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [searchResults, setSearchResults] = useState<{ text: string, sources: NonNullable<GroundingChunk['web']>[] } | null>(null);

  // Fallback para heroContent caso ele venha do contexto como undefined
  const heroContent = assignedHeroContent || {
      title: 'A plataforma completa para',
      highlight: 'seu projeto',
      subtitle: 'Encontre o talento que você precisa para decolar.'
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchTerm.trim()) return;

    setIsLoading(true);
    setSearchResults(null);
    try {
      const results = await searchWithGrounding(searchTerm);
      setSearchResults(results);
    } catch (error) {
      console.error("Search grounding failed:", error);
      alert("Ocorreu um erro durante a busca. Por favor, tente novamente.");
    } finally {
      setIsLoading(false);
    }
  };

  const filteredCategories: ServiceCategory[] = useMemo(() => {
    if (!searchTerm) {
      return allServiceCategories || [];
    }
    return (allServiceCategories || [])
      .map(category => {
        const filteredServices = category.services.filter(service =>
          service.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
          service.professional.name.toLowerCase().includes(searchTerm.toLowerCase())
        );
        return { ...category, services: filteredServices };
      })
      .filter(category => category.services.length > 0);
  }, [allServiceCategories, searchTerm]);


  return (
    <div className="animate-fade-in">
      {/* Hero Section */}
      <section className="relative bg-white text-center py-20 md:py-32 overflow-hidden">
          <div className="absolute inset-0 bg-slate-900/5 bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:32px_32px] [mask-image:radial-gradient(ellipse_50%_50%_at_50%_50%,#000_70%,transparent_100%)]"></div>
          <div className="container mx-auto px-4 relative [perspective:800px]">
              <h1 className="text-4xl md:text-6xl font-extrabold text-slate-900 tracking-tight leading-tight text-3d-effect">
                  {heroContent?.title || ''} <span className={`text-${themeColor}-600`}>{heroContent?.highlight || ''}</span>.
              </h1>
              <p className="mt-4 max-w-2xl mx-auto text-lg text-slate-600 text-3d-effect">
                  {heroContent?.subtitle || ''}
              </p>
              <div className="mt-8 max-w-xl mx-auto">
                  <form onSubmit={handleSearch} className="relative shadow-lg rounded-full">
                      <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none">
                          <SearchIcon className="h-5 w-5 text-slate-400" />
                      </div>
                      <input
                          type="search"
                          value={searchTerm}
                          onChange={(e) => setSearchTerm(e.target.value)}
                          placeholder="Qual talento você busca hoje?"
                          className={`w-full pl-14 pr-6 py-4 bg-white border-2 border-transparent text-slate-900 rounded-full focus:ring-4 focus:ring-${themeColor}-200 focus:outline-none transition-shadow duration-300`}
                      />
                  </form>
              </div>
          </div>
      </section>

      <div className="max-w-7xl mx-auto p-4 md:p-8 space-y-16">
        {isLoading && (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 md:gap-6">
            {[...Array(10)].map((_, i) => <ServiceCardSkeleton key={i} />)}
          </div>
        )}

        {searchResults ? (
          <GroundingSearch results={searchResults} onClear={() => setSearchResults(null)} />
        ) : (
          <>
            {!isLoading && (
              <>
                {isLoggedIn && currentUser?.userType === 'client' ? (
                  <div className={`p-10 rounded-2xl bg-gradient-to-br from-${themeColor}-600 to-${themeColor}-800 text-white flex flex-col items-center text-center shadow-xl`}>
                      <h3 className="text-3xl font-bold">Tem um projeto em mente?</h3>
                      <p className="mt-2 text-white/80 max-w-md">Descreva o que você precisa e deixe que os melhores profissionais encontrem você.</p>
                      <button onClick={() => navigate('requestService')} className="mt-6 bg-white text-slate-800 font-bold py-3 px-6 rounded-full shadow-md transition-all duration-200 ease-in-out transform hover:scale-105 hover:shadow-xl active:scale-100">
                          Solicitar um Serviço
                      </button>
                  </div>
                ) : !isLoggedIn && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <div className={`p-10 rounded-2xl bg-gradient-to-br from-${themeColor}-600 to-${themeColor}-800 text-white flex flex-col items-center text-center shadow-xl`}>
                          <h3 className="text-3xl font-bold">Precisa de um talento?</h3>
                          <p className="mt-2 text-white/80">Publique seu projeto e receba propostas dos melhores profissionais do mercado.</p>
                          <button onClick={() => navigate('login')} className="mt-6 bg-white text-slate-800 font-bold py-3 px-6 rounded-full shadow-md transition-all duration-200 ease-in-out transform hover:scale-105 hover:shadow-xl active:scale-100">
                              Comece Agora
                          </button>
                      </div>
                       <div className="p-10 rounded-2xl bg-gradient-to-br from-slate-700 to-slate-900 text-white flex flex-col items-center text-center shadow-xl">
                          <h3 className="text-3xl font-bold">É um profissional?</h3>
                          <p className="mt-2 text-white/80">Encontre novas oportunidades, conecte-se com clientes e expanda seus negócios.</p>
                          <button onClick={() => navigate('login')} className="mt-6 bg-white text-slate-800 font-bold py-3 px-6 rounded-full shadow-md transition-all duration-200 ease-in-out transform hover:scale-105 hover:shadow-xl active:scale-100">
                              Ofereça Seus Serviços
                          </button>
                      </div>
                  </div>
                )}

                {filteredCategories.length > 0 ? (
                    filteredCategories.map(category => (
                        <ServiceGrid 
                            key={category.title} 
                            title={category.title} 
                            services={category.services} 
                        />
                    ))
                ) : (
                    <p className="text-center text-slate-500">Nenhum serviço encontrado para "{searchTerm}".</p>
                )}
              </>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default Home;

import React from 'react';
import { useAppContext } from '../contexts/AppContext';
import { ArrowLeftIcon } from './Icons';
