const CategoryView: React.FC = () => {
    const { allServiceCategories, viewedCategory, navigate, themeColor } = useAppContext();

    const category = (allServiceCategories || []).find(c => c.title === viewedCategory);

    if (!category) {
        return (
            <div className="text-center p-8">
                <p>Categoria não encontrada.</p>
                <button onClick={() => navigate('home')} className={`mt-4 text-${themeColor}-600`}>Voltar para Início</button>
            </div>
        );
    }

    return (
        <div className="bg-slate-100 min-h-full">
            <header className="bg-white shadow-sm sticky top-0 md:relative z-10">
                <div className="max-w-7xl mx-auto py-4 px-4 sm:px-6 lg:px-8">
                    <button onClick={() => navigate('home')} className="flex items-center gap-2 text-sm font-semibold text-slate-600 hover:text-slate-900">
                        <ArrowLeftIcon className="w-5 h-5" />
                        Voltar para o Início
                    </button>
                </div>
            </header>
            <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
                <h1 className="text-3xl md:text-4xl font-bold text-slate-900 mb-8">{category?.title || 'Categoria'}</h1>
                 <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 md:gap-6">
                    {(category?.services || []).map((service) => (
                        <ServiceCard key={service.name} service={service} categoryTitle={category?.title || ''} />
                    ))}
                </div>
            </main>
        </div>
    );
}

export default CategoryView;

// O SDK é carregado globalmente via index.html, então acessamos 'Parse' do objeto window.
declare const Parse: any;

/**
 * CONFIGURAÇÃO BACK4APP
 * Prioriza variáveis de ambiente (injetadas via Docker ou Vercel).
 * Substitua os valores default pelas suas chaves reais.
 */
const APP_ID = process.env.PARSE_APP_ID || "SEU_APP_ID_AQUI"; 
const JS_KEY = process.env.PARSE_JS_KEY || "SUA_JAVASCRIPT_KEY_AQUI";

if (typeof Parse !== 'undefined') {
    Parse.initialize(APP_ID, JS_KEY);
    Parse.serverURL = 'https://parseapi.back4app.com';
}

export async function testParseConnection() {
  try {
    const TestObject = Parse.Object.extend("TestObject");
    const testObject = new TestObject();
    testObject.set("message", `Hello from ${window.location.hostname} via Docker`);
    const result = await testObject.save();
    console.log("Objeto salvo no Parse com sucesso:", result.id);
    return result.id;
  } catch (error: any) {
    console.error("Erro ao conectar ao Parse:", error);
    throw error;
  }
}

export const parseService = {
    testParseConnection,

    // USUÁRIOS
    saveUser: async (userData: any) => {
        const AppUser = new Parse.Object("AppUser");
        Object.entries(userData).forEach(([key, value]) => AppUser.set(key, value));
        return await AppUser.save();
    },

    getUserByEmail: async (email: string) => {
        const query = new Parse.Query("AppUser");
        query.equalTo("email", email.toLowerCase());
        return await query.first();
    },

    updateUser: async (email: string, data: any) => {
        const query = new Parse.Query("AppUser");
        query.equalTo("email", email.toLowerCase());
        const user = await query.first();
        if (user) {
            Object.entries(data).forEach(([key, value]) => user.set(key, value));
            return await user.save();
        }
    },

    // SOLICITAÇÕES DE SERVIÇO
    createServiceRequest: async (requestData: any) => {
        const Request = new Parse.Object("ServiceRequest");
        Object.entries(requestData).forEach(([key, value]) => Request.set(key, value));
        return await Request.save();
    },

    getServiceRequests: async () => {
        const query = new Parse.Query("ServiceRequest");
        query.descending("createdAt");
        const results = await query.find();
        return results.map((obj: any) => ({ id: obj.id, ...obj.attributes }));
    },

    updateServiceRequestStatus: async (requestId: string, status: string) => {
        const query = new Parse.Query("ServiceRequest");
        try {
            const req = await query.get(requestId);
            req.set("status", status);
            return await req.save();
        } catch (e) {
            const q2 = new Parse.Query("ServiceRequest");
            q2.equalTo("customId", requestId);
            const req = await q2.first();
            if (req) {
                req.set("status", status);
                return await req.save();
            }
        }
    }
};

// O SDK é carregado via script tag no index.html
declare const Parse: any;

/**
 * CONFIGURAÇÃO BACK4APP
 * Tenta ler do ambiente ou usa placeholders.
 */
const getEnv = (key: string) => {
    try {
        // @ts-ignore
        return process.env[key] || "";
    } catch {
        return "";
    }
};

const APP_ID = getEnv("PARSE_APP_ID") || "SEU_APP_ID_REAL"; 
const JS_KEY = getEnv("PARSE_JS_KEY") || "SUA_JS_KEY_REAL";

let isInitialized = false;

const initializeParse = () => {
    if (typeof Parse !== 'undefined' && !isInitialized) {
        try {
            Parse.initialize(APP_ID, JS_KEY);
            Parse.serverURL = 'https://parseapi.back4app.com';
            isInitialized = true;
            console.log("Parse SDK inicializado com sucesso.");
        } catch (e) {
            console.error("Erro ao inicializar Parse SDK:", e);
        }
    }
};

// Tenta inicializar imediatamente
initializeParse();

export async function testParseConnection() {
  initializeParse();
  if (typeof Parse === 'undefined') throw new Error("SDK do Parse não carregado.");

  try {
    const TestObject = Parse.Object.extend("TestObject");
    const testObject = new TestObject();
    testObject.set("message", `Conexão testada em ${new Date().toISOString()}`);
    const result = await testObject.save();
    return result.id;
  } catch (error: any) {
    console.error("Erro de conexão Parse:", error);
    throw error;
  }
}

export const parseService = {
    testParseConnection,

    saveUser: async (userData: any) => {
        initializeParse();
        if (typeof Parse === 'undefined') return null;
        const AppUser = new Parse.Object("AppUser");
        Object.entries(userData).forEach(([key, value]) => AppUser.set(key, value));
        return await AppUser.save();
    },

    getUserByEmail: async (email: string) => {
        initializeParse();
        if (typeof Parse === 'undefined') return null;
        const query = new Parse.Query("AppUser");
        query.equalTo("email", email.toLowerCase());
        return await query.first();
    },

    updateUser: async (email: string, data: any) => {
        initializeParse();
        if (typeof Parse === 'undefined') return null;
        const query = new Parse.Query("AppUser");
        query.equalTo("email", email.toLowerCase());
        const user = await query.first();
        if (user) {
            Object.entries(data).forEach(([key, value]) => user.set(key, value));
            return await user.save();
        }
    },

    createServiceRequest: async (requestData: any) => {
        initializeParse();
        if (typeof Parse === 'undefined') throw new Error("Parse não disponível");
        const Request = new Parse.Object("ServiceRequest");
        Object.entries(requestData).forEach(([key, value]) => Request.set(key, value));
        return await Request.save();
    },

    getServiceRequests: async () => {
        initializeParse();
        if (typeof Parse === 'undefined') return [];
        try {
            const query = new Parse.Query("ServiceRequest");
            query.descending("createdAt");
            const results = await query.find();
            return results.map((obj: any) => ({ id: obj.id, ...obj.attributes }));
        } catch (e) {
            console.warn("Falha ao buscar solicitações do Parse:", e);
            return [];
        }
    },

    updateServiceRequestStatus: async (requestId: string, status: string) => {
        initializeParse();
        if (typeof Parse === 'undefined') return null;
        const query = new Parse.Query("ServiceRequest");
        try {
            const req = await query.get(requestId);
            req.set("status", status);
            return await req.save();
        } catch (e) {
            const q2 = new Parse.Query("ServiceRequest");
            q2.equalTo("customId", requestId);
            const req = await q2.first();
            if (req) {
                req.set("status", status);
                return await req.save();
            }
        }
    }
};

import React, { createContext, useState, useContext, useMemo, useEffect } from 'react';
import { User, Service, Review, ServiceCategory, HeroContent, CreditPackage, ServiceRequest, ClientOrder, ProfessionalOrder, ABTestConfig, PricingTiers, Users, SupportTicket, SupportMessage, Transaction, PaymentConfig } from '../types';
import { servicesData, initialClientOrders, initialProfessionalOrders, initialServiceRequests, allUsers as initialUsers, initialSupportTickets, initialTransactions } from '../data/mockData';
import { secureStorage } from '../utils/secureStorage';
import { parseService } from '../services/parseService';

export type View = 'home' | 'orders' | 'login' | 'profile' | 'credits' | 'chat' | 'professionalProfile' | 'adminPanel' | 'categoryView' | 'marketplace' | 'requestService';

export type ReviewContextType = {
    service: Service;
    orderId: number;
};

type ToastState = {
  message: string;
  type: 'success' | 'error';
  visible: boolean;
};

interface AppContextType {
    currentUser: User | null;
    isLoggedIn: boolean;
    login: (user: User) => void;
    logout: () => void;
    setUserCredits: (newCreditCount: number) => void;
    updateUserProfile: (email: string, updatedProfile: Partial<User>) => void;
    adminChangeUserPassword: (email: string, newPassword: string) => void;
    activeView: View;
    navigate: (view: View) => void;
    viewedService: Service | null;
    viewProfessionalProfile: (service: Service) => void;
    viewedCategory: string | null;
    viewCategory: (categoryTitle: string) => void;
    reviewContext: ReviewContextType | null;
    openReviewModal: (context: ReviewContextType) => void;
    closeReviewModal: () => void;
    submitReview: (serviceName: string, orderId: number, review: Review) => void;
    reviewedOrderIds: number[];
    paymentContext: CreditPackage | null;
    openPaymentModal: (pkg: CreditPackage) => void;
    closePaymentModal: () => void;
    isChangePasswordModalOpen: boolean;
    openChangePasswordModal: () => void;
    closeChangePasswordModal: () => void;
    isForgotPasswordModalOpen: boolean;
    openForgotPasswordModal: () => void;
    closeForgotPasswordModal: () => void;
    themeColor: string;
    setThemeColor: (color: string) => void;
    heroContent: HeroContent;
    setHeroContent: (content: HeroContent) => void;
    allServiceCategories: ServiceCategory[];
    setAllServiceCategories: React.Dispatch<React.SetStateAction<ServiceCategory[]>>;
    appName: string;
    setAppName: (name: string) => void;
    appLogo: string | null;
    setAppLogo: (logo: string | null) => void;
