    setPaymentGateway: (gateway: string) => void;
    paymentConfig: PaymentConfig;
    setPaymentConfig: (config: PaymentConfig) => void;
    toast: ToastState;
    showToast: (message: string, type: 'success' | 'error') => void;
    abTestConfig: ABTestConfig | null;
    startABTest: (variations: HeroContent[]) => void;
    endABTest: () => void;
    assignedHeroContent: HeroContent;
    clientOrders: ClientOrder[];
    setClientOrders: React.Dispatch<React.SetStateAction<ClientOrder[]>>;
    professionalOrders: ProfessionalOrder[];
    setProfessionalOrders: React.Dispatch<React.SetStateAction<ProfessionalOrder[]>>;
    newOrdersCount: number;
    newOpportunitiesCount: number;
    serviceRequests: ServiceRequest[];
    setServiceRequests: React.Dispatch<React.SetStateAction<ServiceRequest[]>>;
    addServiceRequest: (request: Omit<ServiceRequest, 'id' | 'clientId' | 'status' | 'date' | 'unlockCost'>) => void;
    unlockService: (request: ServiceRequest) => void;
    requestServiceContext: { category: string; service: string } | null;
    initiateServiceRequest: (serviceName: string, categoryName: string) => void;
    clearRequestServiceContext: () => void;
    pricingTiers: PricingTiers;
    setPricingTiers: (tiers: PricingTiers) => void;
    allUsers: Users;
    setAllUsers: React.Dispatch<React.SetStateAction<Users>>;
    supportTickets: SupportTicket[];
    addSupportMessage: (messageText: string) => void;
    replyToSupportTicket: (ticketId: number, replyText: string) => void;
    updateSupportTicketStatus: (ticketId: number, status: 'Aberto' | 'Fechado') => void;
    transactions: Transaction[];
