    updateServiceCategory: (oldTitle: string, newTitle: string) => void;
    deleteServiceCategory: (title: string) => void;
    addService: (categoryTitle: string, serviceData: Omit<Service, 'rating' | 'reviewCount' | 'reviews'>) => void;
    updateService: (categoryTitle: string, serviceName: string, updatedServiceData: Partial<Service>) => void;
