import { secureStorage } from '../utils/secureStorage';
import { parseService } from '../services/parseService';

export type View = 'home' | 'orders' | 'login' | 'profile' | 'credits' | 'chat' | 'professionalProfile' | 'adminPanel' | 'categoryView' | 'marketplace' | 'requestService';

interface AppContextType {
    currentUser: User | null;
    isLoggedIn: boolean;
    login: (userData: any) => Promise<void>;
    register: (userData: any) => Promise<void>;
    logout: () => void;
    setUserCredits: (newCreditCount: number) => void;
    updateUserProfile: (email: string, updatedProfile: Partial<User>) => void;
    activeView: View;
    navigate: (view: View) => void;
    toast: { message: string; type: 'success' | 'error'; visible: boolean };
    showToast: (message: string, type: 'success' | 'error') => void;
    verifyEmail: (email: string) => Promise<void>;
    allServiceCategories: ServiceCategory[];
    clientOrders: ClientOrder[];
    professionalOrders: ProfessionalOrder[];
    serviceRequests: ServiceRequest[];
    addServiceRequest: (request: any) => void;
    unlockService: (request: ServiceRequest) => void;
    themeColor: string;
    appName: string;
    appLogo: string | null;
    fontFamily: string;
    pricingTiers: PricingTiers;
    assignedHeroContent: HeroContent;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppContextProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [currentUser, setCurrentUser] = useState<User | null>(() => secureStorage.getItem('chamaai_user') || null);
    const [activeView, setActiveView] = useState<View>('home');
    const [toast, setToast] = useState({ message: '', type: 'success' as 'success' | 'error', visible: false });
    const [serviceRequests, setServiceRequests] = useState<ServiceRequest[]>(initialServiceRequests);
    const [clientOrders, setClientOrders] = useState<ClientOrder[]>(initialClientOrders);
    const [professionalOrders, setProfessionalOrders] = useState<ProfessionalOrder[]>(initialProfessionalOrders);
    const [allServiceCategories] = useState<ServiceCategory[]>(servicesData);

    const showToast = (message: string, type: 'success' | 'error') => {
        setToast({ message, type, visible: true });
        setTimeout(() => setToast(prev => ({ ...prev, visible: false })), 3000);
    };

    const login = async (credentials: any) => {
        try {
            const user = await parseService.logIn(credentials.email, credentials.password);
            const userData = {
                ...user.attributes,
                isEmailVerified: user.get('emailVerified'),
                email: user.get('email')
            } as User;
            setCurrentUser(userData);
            secureStorage.setItem('chamaai_user', userData);
            setActiveView(userData.email === 'conectechserver@gmail.com' ? 'adminPanel' : 'home');
            showToast('Bem-vindo de volta!', 'success');
        } catch (e: any) {
            showToast(e.message || 'Erro ao entrar.', 'error');
            throw e;
        }
    };

    const register = async (userData: any) => {
        try {
            const user = await parseService.signUp(userData);
            const newUser = {
                ...user.attributes,
                isEmailVerified: false,
                email: user.get('email')
            } as User;
            setCurrentUser(newUser);
            secureStorage.setItem('chamaai_user', newUser);
            showToast('Conta criada! Verifique seu e-mail.', 'success');
            setActiveView('home');
        } catch (e: any) {
            showToast(e.message || 'Erro ao cadastrar.', 'error');
            throw e;
        }
    };

    const verifyEmail = async (email: string) => {
        try {
            await parseService.resendVerificationEmail(email);
            showToast('E-mail de verificação enviado!', 'success');
        } catch (e: any) {
            showToast('Erro ao enviar e-mail. Tente novamente.', 'error');
        }
    };

    const logout = () => {
        setCurrentUser(null);
        secureStorage.removeItem('chamaai_user');
        setActiveView('home');
    };

    // Estático para o exemplo, mas pode ser movido para state
    const customization = {
        themeColor: 'sky',
        appName: 'Chama aí',
        appLogo: null,
        fontFamily: 'Inter',
        pricingTiers: { 'Baixa': 2, 'Média': 5, 'Alta': 10 },
        heroContent: { title: 'A plataforma completa para', highlight: 'seu projeto', subtitle: 'Encontre o talento que você precisa.' }
    };

    return (
        <AppContext.Provider value={{ 
            currentUser, isLoggedIn: !!currentUser, login, register, logout, 
            activeView, navigate: (v) => setActiveView(v), toast, showToast, verifyEmail,
            allServiceCategories, clientOrders, professionalOrders, serviceRequests,
            addServiceRequest: () => {}, unlockService: () => {},
            ...customization, assignedHeroContent: customization.heroContent
        } as any}>
            {children}
        </AppContext.Provider>
    );
};

export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext error');
    return context;
};

