    const handleVerify = async () => {
        if(currentUser) {
            await verifyEmail(currentUser.email);
            setSent(true);
            setTimeout(() => setSent(false), 10000); // Reset após 10s
        }
    };

    return (
        <div className={`w-full bg-amber-500 p-3 text-white text-center text-sm font-medium animate-fade-in flex items-center justify-center gap-2 shadow-inner`}>
            <MailIcon className="w-4 h-4" />
            <span>Seu e-mail <b>{currentUser?.email}</b> ainda não foi verificado.</span>
            <button 
                onClick={handleVerify} 
                disabled={sent}
                className={`ml-2 px-3 py-1 bg-white/20 rounded-full font-bold underline hover:bg-white/30 transition-colors disabled:opacity-50 disabled:no-underline`}
            >
                {sent ? 'E-mail enviado! Verifique sua caixa de entrada.' : 'Enviar link de verificação'}
            </button>
        </div>
    );
};

const UserMenu: React.FC<{ currentUser: User; }> = ({ currentUser }) => {
