    const [professionalOrders, setProfessionalOrders] = useState<ProfessionalOrder[]>(initialProfessionalOrders);
    const [allServiceCategories, setAllServiceCategories] = useState<ServiceCategory[]>(servicesData);
    const [allUsers, setAllUsers] = useState<Users>(initialUsers);
    const [transactions, setTransactions] = useState<Transaction[]>(initialTransactions);
    const [supportTickets, setSupportTickets] = useState<SupportTicket[]>(initialSupportTickets);

    // UI State
    const [reviewContext, setReviewContext] = useState<ReviewContextType | null>(null);
    const [paymentContext, setPaymentContext] = useState<CreditPackage | null>(null);
    const [isChangePasswordModalOpen, setIsChangePasswordModalOpen] = useState(false);
    const [isForgotPasswordModalOpen, setIsForgotPasswordModalOpen] = useState(false);
    const [reviewedOrderIds, setReviewedOrderIds] = useState<number[]>([]);
    const [viewedCategory, setViewedCategory] = useState<string | null>(null);
    const [requestServiceContext, setRequestServiceContext] = useState<{ service: string; category: string } | null>(null);

    // Customization State
    const [appName, setAppName] = useState('Chama aí');
    const [appLogo, setAppLogo] = useState<string | null>(null);
    const [fontFamily, setFontFamily] = useState('Inter');
    const [themeColor, setThemeColor] = useState('sky');
    const [pricingTiers, setPricingTiers] = useState<PricingTiers>({ 'Baixa': 2, 'Média': 5, 'Alta': 10 });
    const [heroContent, setHeroContent] = useState<HeroContent>({ title: 'A plataforma completa para', highlight: 'seu projeto', subtitle: 'Encontre o talento que você precisa.' });
    const [abTestConfig, setAbTestConfig] = useState<ABTestConfig>({ active: false, variations: [] });

    const [paymentConfig, setPaymentConfig] = useState<PaymentConfig>({ provider: 'external', environment: 'sandbox' });

    const showToast = (message: string, type: 'success' | 'error') => {
        setToast({ message, type, visible: true });
        setTimeout(() => setToast(prev => ({ ...prev, visible: false })), 3000);
    };

    const login = async (userData: any) => {
        // Implementation for simulation if Parse fails
        setCurrentUser(userData);
        secureStorage.setItem('chamaai_user', userData);
        setActiveView(userData.email === 'conectechserver@gmail.com' ? 'adminPanel' : 'home');
        showToast('Bem-vindo de volta!', 'success');
    };

    const register = async (userData: any) => {
        const newUser = { ...userData, credits: userData.userType === 'professional' ? 50 : 0 };
        setCurrentUser(newUser);
        secureStorage.setItem('chamaai_user', newUser);
        showToast('Conta criada!', 'success');
        setActiveView('home');
    };

    const verifyEmail = async (email: string) => {
        showToast('E-mail de verificação enviado!', 'success');
    };

    const logout = () => {
        setCurrentUser(null);
        secureStorage.removeItem('chamaai_user');
        setActiveView('home');
    };

    const setUserCredits = (credits: number) => {
        if (currentUser) {
            const updated = { ...currentUser, credits };
            setCurrentUser(updated);
            secureStorage.setItem('chamaai_user', updated);
        }
    };

    const updateUserProfile = (email: string, data: Partial<User>) => {
        if (currentUser && currentUser.email === email) {
            const updated = { ...currentUser, ...data };
            setCurrentUser(updated);
            secureStorage.setItem('chamaai_user', updated);
        }
        setAllUsers(prev => ({ ...prev, [email]: { ...prev[email], ...data } }));
        showToast('Perfil atualizado!', 'success');
    };

    const initiateServiceRequest = (service: string, category: string) => {
        setRequestServiceContext({ service, category });
        setActiveView('requestService');
    };

    const unlockService = (request: ServiceRequest) => {
        if (!currentUser) return;
        const cost = request.unlockCost;
        setUserCredits((currentUser.credits || 0) - cost);

        const newOrder: ProfessionalOrder = {
            id: Date.now(),
            service: request.title,
            client: allUsers[request.clientId.toLowerCase()] || { name: 'Cliente', email: request.clientId, userType: 'client' },
            date: new Date().toLocaleDateString(),
            status: 'Contato Liberado',
            locked: false,
            professionalId: currentUser.email
        };
        setProfessionalOrders(prev => [newOrder, ...prev]);
        showToast('Contato desbloqueado!', 'success');
    };

    const completeServiceByProfessional = (orderId: number) => {
        setProfessionalOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Concluído pelo Profissional' } : o));
        setClientOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Concluído pelo Profissional' } : o));
        showToast('Serviço marcado como concluído!', 'success');
    };

    const finalizeServiceByClient = (orderId: number) => {
        setClientOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Finalizado' } : o));
        setProfessionalOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Finalizado' } : o));
        showToast('Serviço finalizado!', 'success');
    };

    const submitReview = (serviceName: string, orderId: number, review: Review) => {
        setReviewedOrderIds(prev => [...prev, orderId]);
        showToast('Avaliação enviada!', 'success');
    };

    const value: AppContextType = {
        currentUser, isLoggedIn: !!currentUser, login, register, logout, setUserCredits, updateUserProfile,
        activeView, navigate: (v) => setActiveView(v), toast, showToast, verifyEmail,
        allServiceCategories, clientOrders, professionalOrders, serviceRequests,
        addServiceRequest: (req) => setServiceRequests(prev => [req, ...prev]),
        unlockService,
        themeColor, appName, appLogo, fontFamily, pricingTiers,
        assignedHeroContent: heroContent,
        reviewContext, closeReviewModal: () => setReviewContext(null), submitReview,
        paymentContext, closePaymentModal: () => setPaymentContext(null),
        isChangePasswordModalOpen, closeChangePasswordModal: () => setIsChangePasswordModalOpen(false),
        openChangePasswordModal: () => setIsChangePasswordModalOpen(true),
        isForgotPasswordModalOpen, closeForgotPasswordModal: () => setIsForgotPasswordModalOpen(false),
        openForgotPasswordModal: () => setIsForgotPasswordModalOpen(true),
        openReviewModal: (ctx) => setReviewContext(ctx),
        reviewedOrderIds,
        completeServiceByProfessional,
        finalizeServiceByClient,
        allUsers, setAllUsers, transactions, supportTickets,
        replyToSupportTicket: (id, text) => {},
        updateSupportTicketStatus: (id, status) => {},
        addSupportMessage: (text) => {},
        approveVerification: (email) => {
            setAllUsers(prev => ({ ...prev, [email]: { ...prev[email], verificationStatus: 'Verified', isVerified: true } }));
            showToast('Profissional verificado!', 'success');
        },
        rejectVerification: (email) => {
            setAllUsers(prev => ({ ...prev, [email]: { ...prev[email], verificationStatus: 'Rejected' } }));
            showToast('Verificação rejeitada.', 'error');
        },
        adminChangeUserPassword: (email, pwd) => showToast('Senha alterada pelo admin.', 'success'),
        updateService: (catTitle, svcName, data) => {
            setAllServiceCategories(prev => prev.map(cat => {
                if (cat.title === catTitle) {
                    return { ...cat, services: cat.services.map(s => s.name === svcName ? { ...s, ...data } : s) };
                }
                return cat;
            }));
        },
        setAppName, setAppLogo, setFontFamily, setThemeColor, setHeroContent, setPricingTiers,
        abTestConfig, startABTest: (vars) => setAbTestConfig({ active: true, variations: vars }),
        endABTest: () => setAbTestConfig({ active: false, variations: [] }),
        paymentConfig, setPaymentConfig, setPaymentGateway: (gw) => setPaymentConfig(p => ({ ...p, provider: gw })),
        viewedCategory, viewCategory: (cat) => { setViewedCategory(cat); setActiveView('categoryView'); },
        initiateServiceRequest, requestServiceContext, clearRequestServiceContext: () => setRequestServiceContext(null),
        newOrdersCount: professionalOrders.filter(o => o.status === 'Novo Pedido').length,
        newOpportunitiesCount: serviceRequests.filter(r => r.status === 'Aguardando Profissionais').length,
        viewedService: null // Simplified for this context
    };

    return (
        <AppContext.Provider value={value}>
            {children}
        </AppContext.Provider>
    );
};

export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext error');
    return context;
};

