const EmailVerificationBanner: React.FC = () => {
    const { currentUser, verifyEmail, checkVerificationStatus, themeColor } = useAppContext();
    const [loading, setLoading] = useState(false);

    const handleResend = async () => {
        if(currentUser) {
            setLoading(true);
            await verifyEmail(currentUser.email);
            setLoading(false);
        }
    };

    return (
        <div className="w-full bg-slate-900 p-2.5 text-white text-center text-xs sm:text-sm font-medium animate-fade-in flex flex-wrap items-center justify-center gap-3 shadow-xl">
            <div className="flex items-center gap-2">
                <div className="w-2 h-2 bg-amber-500 rounded-full animate-pulse"></div>
                <span>Confirme seu e-mail profissional: <b>{currentUser?.email}</b></span>
            </div>
            <div className="flex items-center gap-2">
                <button 
                    onClick={handleResend} 
                    disabled={loading}
                    className="px-3 py-1 bg-white/10 hover:bg-white/20 rounded-full text-[11px] font-bold transition-all disabled:opacity-50"
                >
                    {loading ? 'Enviando...' : 'Reenviar Link'}
                </button>
                <button 
                    onClick={checkVerificationStatus}
                    className="px-3 py-1 bg-blue-600 hover:bg-blue-500 rounded-full text-[11px] font-bold transition-all flex items-center gap-1"
                >
                    <CheckCircleIcon className="w-3 h-3" /> Já verifiquei
                </button>
            </div>
        </div>
    );
};

const UserMenu: React.FC<{ currentUser: User; }> = ({ currentUser }) => {
    const { logout, navigate, themeColor } = useAppContext();
    const [isOpen, setIsOpen] = useState(false);
    const menuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    return (
        <div className="relative" ref={menuRef}>
            <button onClick={() => setIsOpen(!isOpen)} className="flex items-center space-x-2 rounded-full hover:bg-slate-100 transition-all p-1">
                <img className="w-9 h-9 rounded-full ring-2 ring-white shadow-sm" src={currentUser.avatar || `https://i.pravatar.cc/150?u=${currentUser.email}`} alt={currentUser.name} />
            </button>
            {isOpen && (
                <div className="absolute right-0 mt-2 w-64 bg-white rounded-2xl shadow-2xl z-50 ring-1 ring-black/5 animate-fade-in overflow-hidden">
                    <div className="px-4 py-4 bg-slate-50 border-b border-slate-100">
                        <p className="text-sm font-bold text-slate-900 truncate">{currentUser.name}</p>
                        <p className="text-xs text-slate-500 truncate">{currentUser.email}</p>
                        {currentUser.isEmailVerified && (
                             <span className="mt-2 inline-flex items-center gap-1 text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full border border-blue-100">
                                <CheckCircleIcon className="w-3 h-3" /> E-MAIL VERIFICADO
                             </span>
                        )}
                    </div>
                    <div className="p-1">
                        <button onClick={() => { navigate('profile'); setIsOpen(false); }} className="w-full text-left flex items-center px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 rounded-xl transition-colors">
                            <UserIcon className="w-4 h-4 mr-3 text-slate-400" /> Meu Perfil
                        </button>
                        <button onClick={logout} className="w-full text-left flex items-center px-4 py-3 text-sm text-red-600 hover:bg-red-50 rounded-xl transition-colors">
                            <LogoutIcon className="w-4 h-4 mr-3 text-red-400" /> Sair da Conta
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

